public Program(){Runtime.UpdateFrequency=UpdateFrequency.Update10;_booting=true;DrawBoot(0f,"Initialising...");}
public void Save(){var sb=new StringBuilder();sb.Append("SAFE=");sb.Append(_safeMode?"1\n":"0\n");sb.Append("CRAFT=");sb.Append(autoCraft?"1\n":"0\n");sb.Append("SORTERS=");sb.Append(_sortersOn?"1\n":"0\n");foreach(var p in _bpMap){sb.Append(p.Key.ToString());sb.Append(";");sb.Append(p.Value.ToString());sb.Append("\n");}Storage=sb.ToString();}
public void Main(string arg,UpdateType src){if(Runtime.UpdateFrequency!=UpdateFrequency.Update10)Runtime.UpdateFrequency=UpdateFrequency.Update10;if((src&(UpdateType.Terminal|UpdateType.Trigger|UpdateType.Script))!=0){DoCmd(arg);return;}if(_booting){Boot();return;}try{_stepName=(_step<STEP_NAMES.Length)?STEP_NAMES[_step]:"Step "+_step;if(_step==0)S0_Scan();else if(_step==1)S1_FindItems();else if(_step==2)P2Control();else if(_step==3)S3_Assign();else if(_step==4)S4_Stock();else if(_step==5)S5_Sort();else if(_step==6)S6_Balance();else if(_step==7)S7_Turrets();else if(_step==8)S8_Ice();else if(_step==9)S9_Uranium();else if(_step==10)S10_Amounts();else if(_step==11)S11_Autocraft();else if(_step==12)S12_AsmClean();else if(_step==13)S13_Queues();else if(_step==14)S14_Learn();else if(_step==15)S15_OreBalance();else if(_step==16)S16_RefSort();else if(_step==17)S17_InternalSort();else if(_step==18||_step==19)S18_Displays();_step++;if(_step>=TOTAL_STEPS)_step=0;_lastMs=Runtime.LastRunTimeMs;_lastInstr=Runtime.CurrentInstructionCount;}catch(Exception ex){_errCnt++;_lastErr=ex.Message;Log("ERR "+_step+": "+ex.Message);Echo("ERR step "+_step+": "+ex.Message);_step++;if(_step>=TOTAL_STEPS)_step=0;}Echo("AGM PHASE 2 "+_step+"/"+TOTAL_STEPS+" "+_stepName+"\nErr:"+_errCnt+" Ms:"+_lastMs.ToString("F1"));}
void Boot(){string gcd=Me.CustomData;int gi=gcd.IndexOf("group=");_grpTag=gi>=0?gcd.Substring(gi+6).Split('\n')[0].Trim():"";DrawBoot(0f,"Loading blueprints...");LoadBps();LoadVanillaBps();EnsureQuotaTemplate();EnsureP2Cfg();LoadDisplayQuotas();LoadP2Cfg();DrawBoot(0.3f,"Scanning...");S0_Scan();DrawBoot(0.6f,"Finding items...");S1_FindItems();DrawBoot(0.85f,"Binding LCDs...");BindLcds();DrawBoot(1f,"Ready!");_lcdRescanTimer=0;_booting=false;_step=0;}
void LoadBps(){_bpMap.Clear();_itBp.Clear();if(string.IsNullOrEmpty(Storage))return;foreach(var line in Storage.Split('\n')){if(line.StartsWith("SAFE=")){_safeMode=line.EndsWith("1");continue;}if(line.StartsWith("CRAFT=")){autoCraft=line.EndsWith("1");continue;}if(line.StartsWith("DISASM="))continue;if(line.StartsWith("SORTERS=")){_sortersOn=line.EndsWith("1");continue;}if(string.IsNullOrEmpty(line))continue;var p=line.Split(';');if(p.Length<2)continue;MyDefinitionId a=default(MyDefinitionId),b=default(MyDefinitionId);if(MyDefinitionId.TryParse(p[0],out a)&&MyDefinitionId.TryParse(p[1],out b)){_bpMap[a]=b;_itBp[b]=a;_known.Add(a);}}}
void LoadVanillaBps(){foreach(var p in VANILLA_BP){MyDefinitionId item=default(MyDefinitionId),bp=default(MyDefinitionId);if(!MyDefinitionId.TryParse(OB+p.Key,out item)||!MyDefinitionId.TryParse(OB+"BlueprintDefinition/"+p.Value,out bp))continue;if(!_bpMap.ContainsKey(item))_bpMap[item]=bp;if(!_itBp.ContainsKey(bp))_itBp[bp]=item;_known.Add(item);}}
void EnsureQuotaTemplate(){if(Me.CustomData.Contains(QUOTA_START))return;var sb=new StringBuilder();sb.Append("\n");sb.Append(QUOTA_START);sb.Append("\n~ LCD bars show current amount / quota. Use Type/Subtype when names are ambiguous.\n");foreach(var n in ORE_NAMES)sb.Append("Ore/"+n+"=100000\n");foreach(var n in INGOT_NAMES)sb.Append("Ingot/"+n+"=100000\n");foreach(var n in COMP_NAMES)sb.Append("Component/"+n+"=10000\n");foreach(var n in AMMO_NAMES)sb.Append("AmmoMagazine/"+n+"=100\n");foreach(var n in FOOD_SUBS)sb.Append("ConsumableItem/"+n+"=100\n");foreach(var n in MEAL_NAMES)sb.Append("ConsumableItem/"+n+"=100\n");foreach(var n in ING_SUBS)sb.Append("ConsumableItem/"+n+"=500\n");foreach(var n in PHYS_ING)sb.Append("PhysicalObject/"+n+"=500\n");sb.Append("GasContainerObject/HydrogenBottle=20\nOxygenContainerObject/OxygenBottle=20\nSeedItem/Fruit=100\nSeedItem/Grain=100\nSeedItem/Mushrooms=100\nSeedItem/Vegetables=100\n");sb.Append(QUOTA_END);sb.Append("\n");Me.CustomData+=sb.ToString();}
void LoadDisplayQuotas(){_displayQuota.Clear();string cd=Me.CustomData;int s=cd.IndexOf(QUOTA_START),e=cd.IndexOf(QUOTA_END);if(s<0)return;int nl=cd.IndexOf('\n',s);int bs=nl>=0?nl+1:s,be=e>=0?e:cd.Length;if(bs>=be)return;foreach(var line in cd.Substring(bs,be-bs).Split('\n')){string ln=line.Trim();if(string.IsNullOrEmpty(ln)||ln.StartsWith("~")||ln.StartsWith("@"))continue;int eq=ln.IndexOf('=');if(eq<1)continue;string key=ln.Substring(0,eq).Trim();double q;if(!double.TryParse(ln.Substring(eq+1).Trim(),out q)||q<0)continue;_displayQuota[key]=q;if(key.Contains("/")){MyDefinitionId id=default(MyDefinitionId);if(MyDefinitionId.TryParse(OB+key,out id))_known.Add(id);}}}
void EnsureP2Cfg(){if(Me.CustomData.Contains(P2_START))return;Me.CustomData+="\n"+P2_START+"\nBatteryEngineOn=25\nBatteryEngineOff=100\nH2Warn=30\nH2Crit=10\nO2Warn=30\nO2Crit=10\nIceWarn=10000\nIceCrit=1000\nCargoWarn=85\nCargoCrit=98\nUraniumWarn=10\nLargeReactorUranium=200\nSmallReactorUranium=50\nSmallGridReactorUranium=25\n"+P2_END+"\n";}
double P2Val(string k,double d){string cd=Me.CustomData;int s=cd.IndexOf(P2_START),e=cd.IndexOf(P2_END);if(s<0)return d;int p=cd.IndexOf(k+"=",s,StringComparison.OrdinalIgnoreCase);if(p<0||e>0&&p>e)return d;int n=cd.IndexOf('\n',p);double v;return double.TryParse(cd.Substring(p+k.Length+1,(n<0?cd.Length:n)-p-k.Length-1).Trim(),out v)?v:d;}
void LoadP2Cfg(){pBatOn=P2Val("BatteryEngineOn",25);pBatOff=P2Val("BatteryEngineOff",100);pH2Warn=P2Val("H2Warn",30);pH2Crit=P2Val("H2Crit",10);pO2Warn=P2Val("O2Warn",30);pO2Crit=P2Val("O2Crit",10);pIceWarn=P2Val("IceWarn",10000);pIceCrit=P2Val("IceCrit",1000);pCargoWarn=P2Val("CargoWarn",85);pCargoCrit=P2Val("CargoCrit",98);pUWarn=P2Val("UraniumWarn",10);pULarge=P2Val("LargeReactorUranium",200);pUSmall=P2Val("SmallReactorUranium",50);pUSmallGrid=P2Val("SmallGridReactorUranium",25);}
void DoCmd(string arg){if(string.IsNullOrEmpty(arg))return;string c=arg.Trim().ToLower();if(c=="reset"||c=="reboot"){_booting=true;_step=0;_errCnt=0;Log("Reboot.");}else if(c=="safemode"){_safeMode=true;SetSafe();Save();Log("Safe mode ON");}else if(c=="combatmode"){_safeMode=false;SetSafe();Save();Log("Combat mode ON");}else if(c=="sorterson"){_sortersOn=true;SetSorters();Save();Log("Sorters ON");}else if(c=="sortersoff"){_sortersOn=false;SetSorters();Save();Log("Sorters OFF");}else if(c=="autocrafton"){autoCraft=true;Save();Log("Automatic quota control ON");}else if(c=="autocraftoff"){autoCraft=false;Save();Log("Automatic quota control OFF");}else if(c=="phase2cfg"){EnsureP2Cfg();LoadP2Cfg();Log("Phase 2 config loaded");}else if(c=="sort"){_step=5;}else if(c=="asmstatus"){Log("Asm:"+_asm.Count+" BP:"+_bpMap.Count+" LCD:"+_acraftLcds.Count);foreach(var a in _asm)Log((a.IsQueueEmpty?"IDLE ":"QUEUE ")+a.CustomName);}else if(c.StartsWith("page")){AdvanceLcdPage(c.Substring(4));}else if(c=="scanlcds"){BindLcds();Log("LCDs rescanned.");}else if(c=="lcdreset"){_initLcds.Clear();_drawCursor.Clear();_displaySub=0;BindLcds();Log("LCDs reset.");}else if(c=="quotas"){EnsureQuotaTemplate();LoadDisplayQuotas();Log("Display quotas loaded: "+_displayQuota.Count);}}
void S0_Scan(){_all.Clear();_src.Clear();_oreC.Clear();_ingC.Clear();_cmpC.Clear();_ammoC.Clear();_toolC.Clear();_botC.Clear();_foodC.Clear();_seedC.Clear();_ingIC.Clear();_stkC.Clear();_typedC.Clear();_untagged.Clear();_asm.Clear();_learnAsm.Clear();_ref.Clear();_arc.Clear();_react.Clear();_tanks.Clear();_gens.Clear();_bats.Clear();_guns.Clear();_excl.Clear();var connScr=new List<IMyShipConnector>();GridTerminalSystem.GetBlocksOfType<IMyShipConnector>(connScr,c=>HasTag(c,NO_AGM)&&c.Status==MyShipConnectorStatus.Connected);_exclConn.Clear();foreach(var c in connScr){var o=c.OtherConnector;if(o==null)continue;bool otherIsLocal=o.CubeGrid.IsSameConstructAs(Me.CubeGrid);var exConn=otherIsLocal?c:o;if(exConn.CubeGrid!=Me.CubeGrid){_excl.Add(exConn.CubeGrid);_exclConn.Add(exConn);}}_blkScr.Clear();GridTerminalSystem.GetBlocksOfType<IMyTerminalBlock>(_blkScr,b=>b.HasInventory&&b.IsFunctional);foreach(var b in _blkScr)Classify(b);SortPri(_oreC);SortPri(_ingC);SortPri(_cmpC);SortPri(_ammoC);SortPri(_toolC);SortPri(_botC);SortPri(_foodC);SortPri(_seedC);SortPri(_ingIC);_untagged.Sort((a,b)=>((float)b.GetInventory(0).MaxVolume).CompareTo((float)a.GetInventory(0).MaxVolume));foreach(var a in _asm){a.UseConveyorSystem=true;a.CooperativeMode=false;a.Repeating=false;}P2Scan();}
void Classify(IMyTerminalBlock b){if(IsExcluded(b))return;string n=b.CustomName;bool noSort=HasTag(b,NO_SORT),locked=HasTag(b,LOCKED),hidden=HasTag(b,HIDDEN)||!b.ShowInInventory,stock=HasTag(b,STOCK_TAG);if(!hidden)_all.Add(b);var asm=b as IMyAssembler;if(asm!=null){if(!HasTag(b,NO_AGM)&&!HasTag(b,MANUAL)){bool sameGrid=b.CubeGrid.IsSameConstructAs(Me.CubeGrid);bool grpMatch=_grpTag.Length>0&&n.Contains(GRP_PFX+_grpTag+"]");if(HasTag(b,LEARN)||HasTag(b,LEARN_MANY))_learnAsm.Add(asm);bool role=HasTag(b,ASM_TAG)||HasTag(b,BASIC_ASM_TAG);if(sameGrid||grpMatch||role)_asm.Add(asm);}return;}var ref_=b as IMyRefinery;if(ref_!=null){bool sameGridR=b.CubeGrid.IsSameConstructAs(Me.CubeGrid);bool grpMatchR=_grpTag.Length>0&&n.Contains(GRP_PFX+_grpTag+"]");if(sameGridR||grpMatchR){if(b.BlockDefinition.SubtypeId.Contains("ArcFurnace")||b.BlockDefinition.SubtypeId.Contains("Blast"))_arc.Add(ref_);else _ref.Add(ref_);}return;}if(b is IMyReactor){if(b.CubeGrid.IsSameConstructAs(Me.CubeGrid))_react.Add(b as IMyReactor);return;}if(b is IMyGasTank){if(b.CubeGrid.IsSameConstructAs(Me.CubeGrid))_tanks.Add(b as IMyGasTank);return;}if(b is IMyGasGenerator){if(b.CubeGrid.IsSameConstructAs(Me.CubeGrid))_gens.Add(b as IMyGasGenerator);return;}if(b is IMyBatteryBlock){if(b.CubeGrid.IsSameConstructAs(Me.CubeGrid))_bats.Add(b as IMyBatteryBlock);return;}if(b is IMyUserControllableGun){if(b.CubeGrid.IsSameConstructAs(Me.CubeGrid)&&!HasTag(b,NO_AGM)&&!HasTag(b,MANUAL))_guns.Add(b as IMyUserControllableGun);return;}if(noSort||locked)return;if(stock){_stkC.Add(b);return;}bool isMachine=(b is IMyProductionBlock)||(b is IMyShipWelder)||(b is IMyShipGrinder)||(b is IMyShipDrill)||(b is IMyUserControllableGun);bool noPull=HasTag(b,NO_PULL);if(!hidden&&!isMachine&&!noPull)_src.Add(b);bool typed=false;if(HasTag(b,KW_ORE)){_oreC.Add(b);typed=true;}if(HasTag(b,KW_INGOT)){_ingC.Add(b);typed=true;}if(HasTag(b,KW_COMP)){_cmpC.Add(b);typed=true;}if(HasTag(b,KW_AMMO)){_ammoC.Add(b);typed=true;}if(HasTag(b,KW_TOOLS)){_toolC.Add(b);typed=true;}if(HasTag(b,KW_BOTTLES)){_botC.Add(b);typed=true;}if(HasTag(b,KW_FOOD)){_foodC.Add(b);typed=true;}if(HasTag(b,KW_SEEDS)){_seedC.Add(b);typed=true;}if(HasTag(b,KW_ING)){_ingIC.Add(b);typed=true;}if(typed)_typedC.Add(b);else if(b is IMyCargoContainer&&b.CubeGrid.IsSameConstructAs(Me.CubeGrid))_untagged.Add(b);}
void P2Scan(){_pReact.Clear();_pTank.Clear();_pGen.Clear();_pH2Eng.Clear();_pBat.Clear();_pVent.Clear();_pDock.Clear();_pTurret.Clear();_pAsm.Clear();_pRef.Clear();_pAlertLight.Clear();_pSolar.Clear();_pWind.Clear();_pSorter.Clear();var l=new List<IMyTerminalBlock>();GridTerminalSystem.GetBlocksOfType<IMyTerminalBlock>(l,b=>b.CubeGrid.IsSameConstructAs(Me.CubeGrid)&&!IsExcluded(b));foreach(var b in l){var r=b as IMyReactor;if(r!=null&&HasTag(b,P_REACT))_pReact.Add(r);var t=b as IMyGasTank;if(t!=null&&HasTag(b,P_TANK))_pTank.Add(t);var g=b as IMyGasGenerator;if(g!=null&&HasTag(b,P_GEN))_pGen.Add(g);var bat=b as IMyBatteryBlock;if(bat!=null&&HasTag(b,P_BAT))_pBat.Add(bat);var v=b as IMyAirVent;if(v!=null&&HasTag(b,P_VENT))_pVent.Add(v);var d=b as IMyShipConnector;if(d!=null&&HasTag(b,P_DOCK))_pDock.Add(d);var gun=b as IMyUserControllableGun;if(gun!=null&&HasTag(b,P_TURRET))_pTurret.Add(gun);var a=b as IMyAssembler;if(a!=null&&(HasTag(b,ASM_TAG)||HasTag(b,BASIC_ASM_TAG)))_pAsm.Add(a);var rf=b as IMyRefinery;if(rf!=null&&HasTag(b,P_REF))_pRef.Add(rf);var li=b as IMyLightingBlock;if(li!=null&&HasTag(b,P_ALERT))_pAlertLight.Add(li);var pp=b as IMyPowerProducer;if(pp!=null&&HasTag(b,P_SOLAR))_pSolar.Add(pp);else if(pp!=null&&HasTag(b,P_WIND))_pWind.Add(pp);var so=b as IMyConveyorSorter;if(so!=null)_pSorter.Add(so);var fb=b as IMyFunctionalBlock;if(fb!=null&&HasTag(b,P_H2ENG))_pH2Eng.Add(fb);}SetSafe();SetSorters();P2Metrics();}
void P2Metrics(){double cur=0,max=0;foreach(var b in _pBat){cur+=b.CurrentStoredPower;max+=b.MaxStoredPower;}_batPct=max>0?cur/max*100:0;double h=0,o=0;int hc=0,oc=0;foreach(var t in _pTank){if(t.BlockDefinition.SubtypeId.IndexOf("Hydrogen",StringComparison.OrdinalIgnoreCase)>=0){h+=t.FilledRatio;hc++;}else{o+=t.FilledRatio;oc++;}}_h2Pct=hc>0?h/hc*100:0;_o2Pct=oc>0?o/oc*100:0;_uranium=0;var u=MyItemType.MakeIngot("Uranium");foreach(var r in _pReact)_uranium+=(double)r.GetInventory(0).GetItemAmount(u);_ice=0;var ice=MyItemType.MakeOre("Ice");foreach(var g in _pGen)_ice+=(double)g.GetInventory(0).GetItemAmount(ice);double cv=0,cm=0;foreach(var b in _all)for(int i=0;i<b.InventoryCount;i++){cv+=(double)b.GetInventory(i).CurrentVolume;cm+=(double)b.GetInventory(i).MaxVolume;}_cargoPct=cm>0?cv/cm*100:0;P2Alert();}
void P2Control(){LoadP2Cfg();P2Metrics();bool h2=_pReact.Count>0&&_pBat.Count>0&&_uranium<=0&&_batPct<pBatOn;if(_uranium>0||_batPct>=pBatOff)h2=false;foreach(var e in _pH2Eng)e.Enabled=h2;foreach(var g in _pGen)g.AutoRefill=true;RefillBottles();BalanceTanks();SetSafe();SetSorters();}
void BalanceTanks(){double h=0,o=0;int hc=0,oc=0;foreach(var t in _pTank){bool hy=t.BlockDefinition.SubtypeId.IndexOf("Hydrogen",StringComparison.OrdinalIgnoreCase)>=0;if(hy){h+=t.FilledRatio;hc++;}else{o+=t.FilledRatio;oc++;}}foreach(var t in _pTank){bool hy=t.BlockDefinition.SubtypeId.IndexOf("Hydrogen",StringComparison.OrdinalIgnoreCase)>=0;double av=hy?(hc>0?h/hc:0):(oc>0?o/oc:0);t.Stockpile=t.FilledRatio<av-.02;}}
void SetSafe(){foreach(var t in _pTurret)t.Enabled=!_safeMode;}
void SetSorters(){foreach(var s in _pSorter)s.Enabled=_sortersOn;}
void RefillBottles(){foreach(var g in _pGen){var d=g.GetInventory(0);foreach(var b in _botC){if(b==g)continue;var s=b.GetInventory(0);foreach(var n in BOTTLE_NAMES){MyItemType it=MyItemType.Parse(OB+(n=="OxygenBottle"?T_OXY:T_GAS)+"/"+n);double a=(double)s.GetItemAmount(it);if(a>0)XferType(it.ToString(),s,d,a);}}}}
void P2Alert(){_alertLevel=0;var a=new List<string>();if(_pBat.Count>0&&_batPct<pBatOn){_alertLevel=1;a.Add("POWER LOW");}if(_pReact.Count>0){if(_uranium<=0){_alertLevel=Math.Max(_alertLevel,1);a.Add("NO URANIUM");}else if(_uranium<pUWarn){_alertLevel=Math.Max(_alertLevel,1);a.Add("URANIUM LOW");}}bool ht=false,ot=false;foreach(var t in _pTank)if(t.BlockDefinition.SubtypeId.IndexOf("Hydrogen",StringComparison.OrdinalIgnoreCase)>=0)ht=true;else ot=true;if(ht){if(_h2Pct<pH2Crit){_alertLevel=2;a.Add("H2 CRIT");}else if(_h2Pct<pH2Warn){_alertLevel=Math.Max(_alertLevel,1);a.Add("H2 LOW");}}if(ot){if(_o2Pct<pO2Crit){_alertLevel=2;a.Add("O2 CRIT");}else if(_o2Pct<pO2Warn){_alertLevel=Math.Max(_alertLevel,1);a.Add("O2 LOW");}}if(_pGen.Count>0){if(_ice<pIceCrit){_alertLevel=2;a.Add("ICE CRIT");}else if(_ice<pIceWarn){_alertLevel=Math.Max(_alertLevel,1);a.Add("ICE LOW");}}if(_cargoPct>=pCargoCrit){_alertLevel=2;a.Add("CARGO FULL");}else if(_cargoPct>=pCargoWarn){_alertLevel=Math.Max(_alertLevel,1);a.Add("CARGO HIGH");}foreach(var t in _pTurret)if(!t.IsFunctional){_alertLevel=Math.Max(_alertLevel,1);a.Add("TURRET OFFLINE");break;}foreach(var x in _pAsm)if(!x.IsQueueEmpty&&!x.IsProducing){_alertLevel=Math.Max(_alertLevel,1);a.Add("ASSEMBLER STUCK");break;}_alertText=a.Count==0?"ALL SYSTEMS OK":string.Join(" | ",a);Color c=_alertLevel==2?CLR_ERR:_alertLevel==1?CLR_WARN:CLR_OK;foreach(var l in _pAlertLight){l.Enabled=true;l.Color=c;l.BlinkIntervalSeconds=_alertLevel==2?1f:0f;l.BlinkLength=50f;}}
int GetPri(IMyTerminalBlock b){string n=b.CustomName.ToLower();int s=n.IndexOf("[p");if(s<0)return 500000+(int)(b.EntityId%100000);int e=n.IndexOf("]",s);if(e<0)return 500000+(int)(b.EntityId%100000);string t=n.Substring(s+2,e-s-2).Trim();if(t=="max")return 0;if(t=="min")return 999999;int v;return int.TryParse(t,out v)?v:500000+(int)(b.EntityId%100000);}
void SortPri(List<IMyTerminalBlock> l){l.Sort((a,b)=>GetPri(a).CompareTo(GetPri(b)));}
bool HasTag(IMyTerminalBlock b,string tag){return b.CustomName.IndexOf(tag,StringComparison.OrdinalIgnoreCase)>=0||b.CustomData.IndexOf(tag,StringComparison.OrdinalIgnoreCase)>=0;}
bool HasNameTag(IMyTerminalBlock b,string tag){return b.CustomName.IndexOf(tag,StringComparison.OrdinalIgnoreCase)>=0;}
bool HasDataTag(IMyTerminalBlock b,string tag){return b.CustomData.IndexOf(tag,StringComparison.OrdinalIgnoreCase)>=0;}
bool LcdRole(IMyTerminalBlock p,string role){foreach(var x in p.CustomData.Split('\n'))if(x.Trim().Equals(role,StringComparison.OrdinalIgnoreCase))return true;return false;}
bool IsBasicAsm(IMyAssembler a){return HasTag(a,BASIC_ASM_TAG)||a.BlockDefinition.SubtypeId.IndexOf("Basic",StringComparison.OrdinalIgnoreCase)>=0||a.BlockDefinition.SubtypeId.IndexOf("Survival",StringComparison.OrdinalIgnoreCase)>=0;}
IMyTextPanel FindAcraftCfg(){IMyTextPanel best=null;int bestPage=int.MaxValue;foreach(var p in _acraftLcds){int pg=GetLcdPage(p);if(best==null||pg<bestPage){best=p;bestPage=pg;}}return best;}
bool IsExcluded(IMyTerminalBlock b){if(_excl.Contains(b.CubeGrid))return true;foreach(var ec in _exclConn)if(b.CubeGrid.IsSameConstructAs(ec.CubeGrid))return true;return false;}
bool IsPinnedStockLine(string line){string ln=line.Trim();int eq=ln.IndexOf('=');if(eq<0)return false;string amt=ln.Substring(eq+1).Trim();return amt.EndsWith("P",StringComparison.OrdinalIgnoreCase);}
void EnsureTemplateItems(IMyTerminalBlock b,string endTag,string[] names){string cd=b.CustomData;int end=cd.IndexOf(endTag,StringComparison.Ordinal);if(end<0)return;var add=new StringBuilder();foreach(var n in names){if(cd.IndexOf("\n"+n+"=",StringComparison.OrdinalIgnoreCase)>=0||cd.StartsWith(n+"=",StringComparison.OrdinalIgnoreCase))continue;add.Append(n);add.Append(InList(n,BOTTLE_NAMES)?"=20\n":"=0\n");}if(add.Length>0)b.CustomData=cd.Insert(end,add.ToString());}
void S1_FindItems(){foreach(var b in _all){if(!b.HasInventory)continue;for(int ii=0;ii<b.InventoryCount;ii++){_itmScr.Clear();b.GetInventory(ii).GetItems(_itmScr);foreach(var it in _itmScr){var id=it.Type;if(!_known.Contains(id)){_known.Add(id);Log("New: "+id.SubtypeId);}}}}}
void S3_Assign(){if(!autoAssign)return;if(assignNew){int nx=0;if(_oreC.Count==0&&nx<_untagged.Count){string a=" "+KW_ORE;if(oresIngotsOne)a+=" "+KW_INGOT;_untagged[nx].CustomName+=a;Log("Assigned: "+_untagged[nx].CustomName);nx++;}if(_cmpC.Count==0&&nx<_untagged.Count){_untagged[nx].CustomName+=" "+KW_COMP;Log("Assigned: "+_untagged[nx].CustomName);nx++;}if(_ammoC.Count==0&&nx<_untagged.Count){string a=" "+KW_AMMO;if(toolsAmmoBottlesOne){a+=" "+KW_TOOLS+" "+KW_BOTTLES;}Log("Assigned: "+_untagged[nx].CustomName+a);_untagged[nx].CustomName+=a;nx++;}if(_foodC.Count==0&&nx<_untagged.Count){string a=" "+KW_FOOD;if(foodSeedsIngOne){a+=" "+KW_SEEDS+" "+KW_ING;}Log("Assigned: "+_untagged[nx].CustomName+a);_untagged[nx].CustomName+=a;nx++;}}if(unassignEmpty){TryUnasgn(_oreC,KW_ORE);TryUnasgn(_ingC,KW_INGOT);TryUnasgn(_cmpC,KW_COMP);TryUnasgn(_ammoC,KW_AMMO);TryUnasgn(_toolC,KW_TOOLS);TryUnasgn(_botC,KW_BOTTLES);TryUnasgn(_foodC,KW_FOOD);TryUnasgn(_seedC,KW_SEEDS);TryUnasgn(_ingIC,KW_ING);}}
void TryUnasgn(List<IMyTerminalBlock> c,string kw){if(c.Count<=1)return;IMyTerminalBlock sched;if(_pendingUnasgn.TryGetValue(kw,out sched)){_pendingUnasgn.Remove(kw);if(sched.GetInventory(0).ItemCount==0&&!sched.CustomName.Contains("[P")){sched.CustomName=sched.CustomName.Replace(" "+kw,"").Replace(kw,"").TrimEnd();Log("Unassigned: "+sched.CustomName);}return;}int cnt=0;IMyTerminalBlock cand=null;foreach(var b in c){if(b.CustomName.Contains("[P"))continue;if(b.GetInventory(0).ItemCount==0){cand=b;cnt++;}}if(cnt>1&&cand!=null)_pendingUnasgn[kw]=cand;}
void S4_Stock(){foreach(var b in _stkC){if(!b.CustomData.Contains(STOCK_START)){WriteStockTmpl(b);Log("Stock tmpl written: "+b.CustomName);continue;}EnsureTemplateItems(b,STOCK_END,AMMO_NAMES);string cd=b.CustomData;int s=cd.IndexOf(STOCK_START),e=cd.IndexOf(STOCK_END);if(s<0)continue;int nl=cd.IndexOf('\n',s);int bs=nl>=0?nl+1:s;int be=e>=0?e:cd.Length;if(bs>=be)continue;var inv=b.GetInventory(0);var stockLines=new List<string>(cd.Substring(bs,be-bs).Split('\n'));stockLines.Sort((a,z)=>IsPinnedStockLine(z).CompareTo(IsPinnedStockLine(a)));foreach(var line in stockLines){string ln=line.Trim();if(string.IsNullOrEmpty(ln)||ln.StartsWith("~")||ln.StartsWith("@")||ln.StartsWith("~~~"))continue;int eq=ln.IndexOf('=');if(eq<0)continue;string key=ln.Substring(0,eq).Trim(),amt=ln.Substring(eq+1).Trim();if(string.IsNullOrEmpty(key)||string.IsNullOrEmpty(amt))continue;bool pin=amt.Length>0&&(amt[amt.Length-1]=='P'||amt[amt.Length-1]=='p');if(pin)amt=amt.Substring(0,amt.Length-1).Trim();int mode=STOCK_NORMAL;bool fill=amt.ToLower()=="all";double want=0;if(fill){mode=STOCK_FILL;}else{if(amt.Length>0&&(amt[amt.Length-1]=='M'||amt[amt.Length-1]=='m')){mode=STOCK_MIN;amt=amt.Substring(0,amt.Length-1);}else if(amt.Length>0&&(amt[amt.Length-1]=='L'||amt[amt.Length-1]=='l')){mode=STOCK_LIMIT;amt=amt.Substring(0,amt.Length-1);}if(!double.TryParse(amt,out want))continue;if(want<0)continue;}MyItemType it=ResolveItem(key);string ts=it.ToString();double cur=(double)inv.GetItemAmount(it);if(mode==STOCK_LIMIT){if(cur<=want)continue;double ex=cur-want;foreach(var a in _src){if(a==b||!a.HasInventory)continue;var di=a.GetInventory(0);if(!InvNotFull(di))continue;ex-=XferType(ts,inv,di,ex);if(ex<=0)break;}continue;}if(mode==STOCK_FILL){if(!InvNotFull(inv))continue;foreach(var a in _src){if(a==b||!a.HasInventory)continue;var si2=a.GetInventory(0);double av=(double)si2.GetItemAmount(it);if(av<=0)continue;XferType(ts,si2,inv,av);if(!InvNotFull(inv))break;}continue;}if(cur<want){double nd=want-cur;foreach(var a in _src){if(a==b||!a.HasInventory)continue;var si2=a.GetInventory(0);double av=(double)si2.GetItemAmount(it);if(av<=0)continue;double moved=XferType(ts,si2,inv,Math.Min(nd,av));if(moved>0)Log("Stock +"+Fmt(moved)+" "+key);nd-=moved;if(nd<=0)break;}}if(mode==STOCK_NORMAL){cur=(double)inv.GetItemAmount(it);if(cur>want){double ex=cur-want;foreach(var a in _src){if(a==b||!a.HasInventory)continue;var di=a.GetInventory(0);if(!InvNotFull(di))continue;ex-=XferType(ts,inv,di,ex);if(ex<=0)break;}}}}}}
MyItemType ResolveItem(string key){if(key.Contains("/")){try{return MyItemType.Parse(OB+key);}catch{}}if(_known.Count>0){string[] tids2=new string[]{T_AMMO,T_COMP,T_TOOL,T_INGOT,T_ORE,T_CON,T_SEED,T_OXY,T_GAS,T_PHYS,T_DATA};foreach(var t in tids2){MyItemType c2;try{c2=MyItemType.Parse(OB+t+"/"+key);}catch{continue;}MyDefinitionId id2=c2;if(_known.Contains(id2))return c2;}}string[] order=new string[]{T_AMMO,T_COMP,T_INGOT,T_ORE,T_TOOL,T_CON,T_SEED,T_OXY,T_GAS,T_PHYS,T_DATA};foreach(var t in order){try{return MyItemType.Parse(OB+t+"/"+key);}catch{}}return MyItemType.MakeComponent(key);}
void S5_Sort(){switch(_sortSub){case 0:Move(T_ORE,_oreC);break;case 1:Move(T_INGOT,_ingC);break;case 2:Move(T_COMP,_cmpC);break;case 3:Move(T_TOOL,_toolC);break;case 4:Move(T_AMMO,_ammoC);break;case 5:Move(T_OXY,_botC);break;case 6:Move(T_GAS,_botC);break;case 7:Move(T_DATA,_toolC);break;case 8:SortFood(T_CON);break;case 9:SortFood(T_PHYS);break;case 10:MoveOpt(T_SEED,_seedC);break;}_sortSub++;if(_sortSub>10)_sortSub=0;}
void Move(string tid,List<IMyTerminalBlock> dests){if(dests.Count==0)return;IMyInventory dInv=null;for(int i=0;i<dests.Count;i++){if(InvNotFull(dests[i].GetInventory(0))){dInv=dests[i].GetInventory(0);break;}}if(dInv==null)return;for(int si=0;si<_src.Count;si++){var sb=_src[si];if(!sb.HasInventory)continue;if(IsCorrect(sb,tid))continue;var sInv=sb.GetInventory(0);var items=new List<MyInventoryItem>();sInv.GetItems(items);for(int ii=items.Count-1;ii>=0;ii--){if(!items[ii].Type.TypeId.ToString().Contains(tid))continue;if(!InvNotFull(dInv)){dInv=null;for(int d=0;d<dests.Count;d++){if(InvNotFull(dests[d].GetInventory(0))){dInv=dests[d].GetInventory(0);break;}}if(dInv==null)return;}var dItems=new List<MyInventoryItem>();dInv.GetItems(dItems);int ds=-1;for(int d=0;d<dItems.Count;d++){if(dItems[d].Type==items[ii].Type){ds=d;break;}}if(ds>=0)sInv.TransferItemTo(dInv,ii,ds,true,null);else sInv.TransferItemTo(dInv,ii,null,true,null);}}}
void MoveOpt(string tid,List<IMyTerminalBlock> dests){if(dests.Count>0)Move(tid,dests);}
bool IsCorrect(IMyTerminalBlock b,string tid){string n=b.CustomName;if(tid==T_ORE)return n.Contains(KW_ORE);if(tid==T_INGOT)return n.Contains(KW_INGOT);if(tid==T_COMP)return n.Contains(KW_COMP);if(tid==T_AMMO)return n.Contains(KW_AMMO);if(tid==T_TOOL)return n.Contains(KW_TOOLS);if(tid==T_OXY||tid==T_GAS)return n.Contains(KW_BOTTLES);if(tid==T_SEED)return n.Contains(KW_SEEDS);if(tid==T_CON)return n.Contains(KW_TOOLS)||n.Contains(KW_FOOD)||n.Contains(KW_ING);if(tid==T_PHYS)return n.Contains(KW_ING)||n.Contains(KW_TOOLS);return false;}
List<IMyTerminalBlock> FoodDest(string tid,string sub){if(tid.Contains(T_PHYS)){foreach(var s in PHYS_ING)if(sub==s)return _ingIC.Count>0?_ingIC:null;return null;}foreach(var s in ING_SUBS)if(sub==s)return _ingIC.Count>0?_ingIC:(_foodC.Count>0?_foodC:null);return _foodC.Count>0?_foodC:null;}
void SortFood(string tid){for(int si=0;si<_src.Count;si++){var sb=_src[si];if(!sb.HasInventory)continue;var sInv=sb.GetInventory(0);var items=new List<MyInventoryItem>();sInv.GetItems(items);for(int ii=items.Count-1;ii>=0;ii--){var it=items[ii];string typeId=it.Type.TypeId.ToString(),sub=it.Type.SubtypeId.ToString();if(!typeId.Contains(tid))continue;var dl=FoodDest(typeId,sub);if(dl==null)continue;bool ok=false;foreach(var d in dl)if(sb==d){ok=true;break;}if(ok)continue;IMyInventory dInv=null;foreach(var d in dl)if(InvNotFull(d.GetInventory(0))){dInv=d.GetInventory(0);break;}if(dInv==null)continue;var di=new List<MyInventoryItem>();dInv.GetItems(di);int ds=-1;for(int d=0;d<di.Count;d++)if(di[d].Type==it.Type){ds=d;break;}if(ds>=0)sInv.TransferItemTo(dInv,ii,ds,true,null);else sInv.TransferItemTo(dInv,ii,null,true,null);}}}
void S6_Balance(){if(!balanceContainers)return;switch(_balSub){case 0:BalCat(_oreC,T_ORE);break;case 1:BalCat(_ingC,T_INGOT);break;case 2:BalCat(_cmpC,T_COMP);break;case 3:BalCat(_ammoC,T_AMMO);break;case 4:BalCat(_toolC,T_TOOL);break;case 5:BalCat(_botC,T_GAS);break;}_balSub++;if(_balSub>5)_balSub=0;}
void BalCat(List<IMyTerminalBlock> c,string tf){var sg=new List<IMyTerminalBlock>();foreach(var b in c)if(b.InventoryCount==1&&b.CubeGrid.IsSameConstructAs(Me.CubeGrid))sg.Add(b);if(sg.Count<2)return;var tot=new Dictionary<MyItemType,double>();var sc=new List<MyInventoryItem>();foreach(var b in sg){sc.Clear();b.GetInventory(0).GetItems(sc);foreach(var it in sc){if(!it.Type.TypeId.ToString().Contains(tf))continue;if(tot.ContainsKey(it.Type))tot[it.Type]+=(double)it.Amount;else tot[it.Type]=(double)it.Amount;}}var tgt=new Dictionary<MyItemType,double>();foreach(var p in tot)tgt[p.Key]=Math.Floor(p.Value/sg.Count);for(int si=0;si<sg.Count;si++){var sInv=sg[si].GetInventory(0);sc.Clear();sInv.GetItems(sc);var hv=new Dictionary<MyItemType,double>();foreach(var it in sc){if(hv.ContainsKey(it.Type))hv[it.Type]+=(double)it.Amount;else hv[it.Type]=(double)it.Amount;}foreach(var p in tot){double here=0;hv.TryGetValue(p.Key,out here);double tg=0;tgt.TryGetValue(p.Key,out tg);if(here<=tg+1)continue;for(int di=0;di<sg.Count;di++){if(di==si)continue;var dInv=sg[di].GetInventory(0);double there=(double)dInv.GetItemAmount(p.Key);if(there>=tg-1)continue;double amt=Math.Min(tg-there,here-tg);if(amt<=0)continue;XferType(p.Key.ToString(),sInv,dInv,amt);here-=amt;if(here<=tg+1)break;}}}}
void S7_Turrets(){if(!fillTurrets||_guns.Count==0)return;foreach(var gun in _guns){if(gun==null||!gun.IsFunctional||!gun.HasInventory)continue;var dst=gun.GetInventory(0);foreach(var p in TURRET_AMMO_TARGETS){MyItemType it;try{it=MyItemType.MakeAmmo(p.Key);}catch{continue;}if(!dst.CanItemsBeAdded((MyFixedPoint)1,it))continue;double cur=(double)dst.GetItemAmount(it),need=p.Value-cur;if(need<=0)continue;need=PullAmmoToTurret(it,dst,need,_ammoC);if(need>0)PullAmmoToTurret(it,dst,need,_src);}}}
double PullAmmoToTurret(MyItemType it,IMyInventory dst,double need,List<IMyTerminalBlock> srcs){string ts=it.ToString();foreach(var b in srcs){if(need<=0)break;if(b==null||!b.HasInventory)continue;var src=b.GetInventory(0);if(src==dst)continue;double av=(double)src.GetItemAmount(it);if(av<=0)continue;need-=XferType(ts,src,dst,Math.Min(need,av));}return need;}
void S8_Ice(){if(!iceBalance||_pGen.Count==0)return;PushToMachines(MyItemType.MakeOre("Ice"),_pGen.ConvertAll(g=>g as IMyTerminalBlock));}
double ReactorTarget(IMyReactor r){if(r.BlockDefinition.SubtypeId.IndexOf("Large",StringComparison.OrdinalIgnoreCase)>=0)return pULarge;return r.CubeGrid.GridSizeEnum==MyCubeSize.Small?pUSmallGrid:pUSmall;}
void S9_Uranium(){if(!uraniumBalance||_pReact.Count==0)return;var it=MyItemType.MakeIngot("Uranium");foreach(var r in _pReact){double target=ReactorTarget(r),need=target-(double)r.GetInventory(0).GetItemAmount(it);if(need<=0)continue;foreach(var b in _ingC){if(need<=0)break;var s=b.GetInventory(0);double a=(double)s.GetItemAmount(it);if(a>0)need-=XferType(it.ToString(),s,r.GetInventory(0),Math.Min(a,need));}}}
void PushToMachines(MyItemType it,List<IMyTerminalBlock> mach){if(mach.Count==0)return;string ts=it.ToString();double[] cur=new double[mach.Count];double inMach=0;for(int i=0;i<mach.Count;i++){if(!mach[i].HasInventory)continue;cur[i]=(double)mach[i].GetInventory(0).GetItemAmount(it);inMach+=cur[i];}double inStore=0;foreach(var b in _all){bool m=false;foreach(var mc in mach)if(b==mc){m=true;break;}if(m||!b.HasInventory)continue;inStore+=(double)b.GetInventory(0).GetItemAmount(it);}if(inStore<=0)return;double tgt=(inMach+inStore)/mach.Count;for(int mi=0;mi<mach.Count;mi++){if(!mach[mi].HasInventory)continue;double nd=tgt-cur[mi];if(nd<=1)continue;var mInv=mach[mi].GetInventory(0);foreach(var b in _all){bool m=false;foreach(var mc in mach)if(b==mc){m=true;break;}if(m||!b.HasInventory)continue;var sInv=b.GetInventory(0);double av=(double)sInv.GetItemAmount(it);if(av<=0)continue;nd-=XferType(ts,sInv,mInv,Math.Min(nd,av));if(nd<=1)break;}}}
void S10_Amounts(){_gAmt.Clear();foreach(var b in _all){if(!b.HasInventory)continue;for(int ii=0;ii<b.InventoryCount;ii++){_itmScr.Clear();b.GetInventory(ii).GetItems(_itmScr);foreach(var it in _itmScr){if(_gAmt.ContainsKey(it.Type))_gAmt[it.Type]+=(double)it.Amount;else _gAmt[it.Type]=(double)it.Amount;}}}_qAmt.Clear();_dQAmt.Clear();foreach(var a in _asm){var qm=a.Mode==MyAssemblerMode.Disassembly?_dQAmt:_qAmt;_queScr.Clear();a.GetQueue(_queScr);foreach(var q in _queScr){if(qm.ContainsKey(q.BlueprintId))qm[q.BlueprintId]+=(double)q.Amount;else qm[q.BlueprintId]=(double)q.Amount;}}}
void S11_Autocraft(){if(!autoCraft)return;if(_asm.Count==0)return;foreach(var a in _asm)if(a.IsQueueEmpty&&!HasTag(a,DSM_ONLY))a.Mode=MyAssemblerMode.Assembly;_acraftLcds.Clear();_blkScr.Clear();GridTerminalSystem.GetBlocksOfType<IMyTextPanel>(_blkScr,p=>p.IsSameConstructAs(Me)&&HasNameTag(p,AGM_TAG)&&(LcdRole(p,"Autocraft")||LcdRole(p,"Crafting")));foreach(var b in _blkScr){var p=b as IMyTextPanel;if(p!=null)_acraftLcds.Add(p);}_acraftCfg=FindAcraftCfg();if(_acraftCfg!=null){if(!_acraftCfg.CustomData.Contains(ACRAFT_START))WriteAcraftTmpl(_acraftCfg);EnsureTemplateItems(_acraftCfg,ACRAFT_END,AMMO_NAMES);EnsureTemplateItems(_acraftCfg,ACRAFT_END,BOTTLE_NAMES);}if(basicIngotCraft&&_ref.Count==0&&_arc.Count==0){MyDefinitionId st=default(MyDefinitionId),bp=default(MyDefinitionId);MyDefinitionId.TryParse(OB+T_ORE+"/Stone",out st);MyDefinitionId.TryParse(OB+"BlueprintDefinition/Position0010_StoneOreToIngotBasic",out bp);double sa=0;_gAmt.TryGetValue(st,out sa);if(sa>100&&bp!=default(MyDefinitionId)){double bat=Math.Floor(sa/100.0/Math.Max(1,_asm.Count));if(bat>=1)foreach(var a in _asm)if(a.CanUseBlueprint(bp)&&a.IsQueueEmpty)a.AddQueueItem(bp,(MyFixedPoint)bat);}}foreach(var lcd in _acraftLcds){if(lcd!=_acraftCfg)continue;string cd=lcd.CustomData;if(string.IsNullOrEmpty(cd))continue;int as2=cd.IndexOf(ACRAFT_START),ae=cd.IndexOf(ACRAFT_END);if(as2<0)continue;int nl=cd.IndexOf('\n',as2);int bs=nl>=0?nl+1:as2;int be=ae>=0?ae:cd.Length;if(bs>=be)continue;cd=cd.Substring(bs,be-bs);foreach(var line in cd.Split('\n')){string ln=line.Trim();if(string.IsNullOrEmpty(ln)||ln.StartsWith("~")||ln.StartsWith("@")||ln.StartsWith("~~~"))continue;int eq=ln.IndexOf('=');if(eq<0)continue;string sub=ln.Substring(0,eq).Trim(),amt=ln.Substring(eq+1).Trim();if(InList(sub,IGNORE_AMMO))continue;bool dm=amt.Length>0&&(amt[amt.Length-1]=='D'||amt[amt.Length-1]=='d');if(dm)amt=amt.Substring(0,amt.Length-1);double want=0;if(!double.TryParse(amt,out want))continue;if(want<=0&&!dm)continue;MyDefinitionId iid=default(MyDefinitionId);if(!TryResId(sub,out iid))continue;double cur=0;_gAmt.TryGetValue(iid,out cur);MyDefinitionId bid;if(!_bpMap.TryGetValue(iid,out bid))continue;double inQ=0,inD=0;_qAmt.TryGetValue(bid,out inQ);_dQAmt.TryGetValue(bid,out inD);if(!dm&&cur<want-want*asmMargin){double tq=Math.Ceiling(want-cur-inQ);if(tq>0)EnqueueAsm(bid,tq,false);}if(cur>want+want*dasmMargin){double td=Math.Ceiling(cur-want-inD);if(td>0)EnqueueAsm(bid,td,true);}}}}
bool TryResId(string sub,out MyDefinitionId id){id=default(MyDefinitionId);string[] tids=new string[]{T_COMP,T_AMMO,T_OXY,T_GAS,T_TOOL,T_INGOT,T_ORE,T_CON,T_SEED};foreach(var t in tids){MyDefinitionId c;if(!MyDefinitionId.TryParse(OB+t+"/"+sub,out c))continue;if(_known.Contains(c)){id=c;return true;}}foreach(var k in _known){if(k.SubtypeId.ToString().ToLower()==sub.ToLower()){id=k;return true;}}return false;}
bool OffloadAssembly(IMyAssembler src){if(src.Mode!=MyAssemblerMode.Assembly||src.IsQueueEmpty)return true;_queScr.Clear();src.GetQueue(_queScr);var dst=new List<IMyAssembler>();foreach(var q in _queScr){IMyAssembler d=null;foreach(var a in _asm)if(a!=src&&!HasTag(a,DSM_ONLY)&&a.Mode!=MyAssemblerMode.Disassembly&&a.CanUseBlueprint(q.BlueprintId)){d=a;break;}if(d==null)return false;dst.Add(d);}for(int i=0;i<_queScr.Count;i++)dst[i].AddQueueItem(_queScr[i].BlueprintId,_queScr[i].Amount);src.ClearQueue();Log("Advanced assembler released for automatic disassembly");return true;}
void EnqueueAsm(MyDefinitionId bp,double amt,bool dsm){var valid=new List<IMyAssembler>();foreach(var a in _asm){if(dsm&&(HasTag(a,ASM_ONLY)||IsBasicAsm(a)))continue;if(!dsm&&(HasTag(a,DSM_ONLY)||(a.Mode==MyAssemblerMode.Disassembly&&!a.IsQueueEmpty)))continue;if(!a.CanUseBlueprint(bp))continue;if(!dsm&&IsBasicAsm(a))valid.Insert(0,a);else valid.Add(a);}if(valid.Count==0)return;if(dsm){foreach(var a in valid){if(!OffloadAssembly(a))continue;a.Mode=MyAssemblerMode.Disassembly;a.AddQueueItem(bp,(MyFixedPoint)amt);Log("Auto-disassembling "+amt.ToString("F0")+"x "+bp.SubtypeId);break;}return;}if(splitAsm&&valid.Count>1){double ea=Math.Ceiling(amt/valid.Count),rem=amt;foreach(var a in valid){double bt=Math.Min(ea,rem);if(bt<1)break;a.InsertQueueItem(0,bp,(MyFixedPoint)bt);rem-=bt;}}else valid[0].InsertQueueItem(0,bp,(MyFixedPoint)amt);Log("Queued "+amt.ToString("F0")+"x "+bp.SubtypeId);}
List<IMyTerminalBlock> ItemDest(MyInventoryItem x){string t=x.Type.TypeId.ToString(),s=x.Type.SubtypeId.ToString();if(t.Contains(T_COMP))return _cmpC;if(t.Contains(T_AMMO))return _ammoC;if(t.Contains(T_TOOL)||t.Contains(T_DATA))return _toolC;if(t.Contains(T_OXY)||t.Contains(T_GAS))return _botC;if(t.Contains(T_CON)||t.Contains(T_PHYS))return FoodDest(t,s);return null;}
void S12_AsmClean(){if(!cleanAsm)return;foreach(var a in _asm){var inv=a.GetInventory(1);if((float)inv.CurrentVolume==0f)continue;_itmScr.Clear();inv.GetItems(_itmScr);for(int i=_itmScr.Count-1;i>=0;i--){var dl=ItemDest(_itmScr[i]);if(dl==null)continue;foreach(var c in dl){var d=c.GetInventory(0);if(!InvNotFull(d))continue;inv.TransferItemTo(d,i,null,true,null);break;}}}}
void S13_Queues(){if(sortAsmQueue)SortAsmQ();if(splitAsm)SplitAsmTasks();}
void SortAsmQ(){foreach(var a in _asm){if(a.Mode==MyAssemblerMode.Disassembly)continue;if(_skipAsmQ.Remove(a.EntityId))continue;_queScr.Clear();a.GetQueue(_queScr);if(_queScr.Count<2)continue;int li=0;double la=double.MaxValue;for(int i=0;i<_queScr.Count;i++){MyDefinitionId id=default(MyDefinitionId);_itBp.TryGetValue(_queScr[i].BlueprintId,out id);double h=0;_gAmt.TryGetValue(id,out h);if(h<la){la=h;li=i;}}if(li!=0){a.MoveQueueItemRequest(_queScr[li].ItemId,0);_skipAsmQ.Add(a.EntityId);}}}
void SplitAsmTasks(){var busy=new List<IMyAssembler>();var idle=new List<IMyAssembler>();foreach(var a in _asm){if(a.Mode==MyAssemblerMode.Disassembly)continue;if(!a.IsQueueEmpty)busy.Add(a);else idle.Add(a);}if(busy.Count==0||idle.Count==0)return;IMyAssembler best=null;double most=0;foreach(var a in busy){_queScr.Clear();a.GetQueue(_queScr);double t=0;foreach(var q in _queScr)t+=(double)q.Amount;if(t>most){most=t;best=a;}}if(best==null)return;_queScr.Clear();best.GetQueue(_queScr);for(int i=0;i<_queScr.Count;i++){double amt=(double)_queScr[i].Amount;if(amt<10)continue;double sp=Math.Floor(amt/(idle.Count+1));if(sp<1)continue;foreach(var a in idle){if(!a.CanUseBlueprint(_queScr[i].BlueprintId))continue;a.InsertQueueItem(0,_queScr[i].BlueprintId,(MyFixedPoint)sp);}break;}}
void S14_Learn(){if(_learnAsm.Count==0)return;if(_lrnAsm!=null){_queScr.Clear();_lrnAsm.GetQueue(_queScr);var out_=new List<MyInventoryItem>();_lrnAsm.GetInventory(1).GetItems(out_);if(_queScr.Count==1&&_lrnAsm.Mode==MyAssemblerMode.Assembly&&_queScr[0].BlueprintId==_lrnBp&&out_.Count>0){MyDefinitionId iid=out_[0].Type;_bpMap[iid]=_lrnBp;_itBp[_lrnBp]=iid;_known.Add(iid);_lrnAsm.ClearQueue();if(!_lrnAsm.CustomName.Contains(LEARN_MANY))_lrnAsm.CustomName=_lrnName.Replace(" "+LEARN,"").Replace(LEARN,"").TrimEnd();Log("Learned: "+iid.SubtypeId);_lrnAsm=null;_lrnBp=default(MyDefinitionId);}else _lrnAsm=null;return;}foreach(var a in _learnAsm){_queScr.Clear();a.GetQueue(_queScr);if(_queScr.Count==1&&a.Mode==MyAssemblerMode.Assembly){_lrnAsm=a;_lrnBp=_queScr[0].BlueprintId;_lrnName=a.CustomName;break;}}}
void CleanRefineries(List<IMyRefinery> all){foreach(var r in all){if(r.InventoryCount<2)continue;var s=r.GetInventory(1);_itmScr.Clear();s.GetItems(_itmScr);for(int i=_itmScr.Count-1;i>=0;i--)foreach(var c in _ingC){if(!InvNotFull(c.GetInventory(0)))continue;if(s.TransferItemTo(c.GetInventory(0),i,null,true,null))break;}}}
void FeedRefineries(List<IMyRefinery> all){foreach(var r in all){if(!r.IsFunctional||!r.Enabled)continue;var d=r.GetInventory(0);if((double)d.CurrentVolume>(double)d.MaxVolume*.45)continue;MyItemType best=default(MyItemType);bool found=false;double low=double.MaxValue,av=0;foreach(var c in _oreC){_itmScr.Clear();c.GetInventory(0).GetItems(_itmScr);foreach(var q in _itmScr){if(!q.Type.TypeId.ToString().Contains(T_ORE)||q.Type.SubtypeId.ToString()=="Ice"||!d.CanItemsBeAdded((MyFixedPoint)1,q.Type))continue;MyDefinitionId ing=default(MyDefinitionId);MyDefinitionId.TryParse(OB+T_INGOT+"/"+q.Type.SubtypeId,out ing);double h=0;_gAmt.TryGetValue(ing,out h);if(h<low){found=true;low=h;best=q.Type;av=(double)q.Amount;}}}if(!found)continue;double need=Math.Min(av,10000);foreach(var c in _oreC){if(need<=0)break;need-=XferType(best.ToString(),c.GetInventory(0),d,need);}}}
void S15_OreBalance(){if(!oreBalance)return;var all=new List<IMyRefinery>();all.AddRange(_ref);all.AddRange(_arc);if(all.Count==0)return;CleanRefineries(all);FeedRefineries(all);if(all.Count<2)return;var types=new List<MyItemType>();var tmp=new List<MyInventoryItem>();foreach(var r in all){tmp.Clear();r.GetInventory(0).GetItems(tmp);foreach(var it in tmp)if(!types.Contains(it.Type))types.Add(it.Type);}foreach(var ore in types){double tot=0;foreach(var r in all)tot+=(double)r.GetInventory(0).GetItemAmount(ore);if(tot<=0)continue;double tgt=tot/all.Count;for(int si=0;si<all.Count;si++){double h=(double)all[si].GetInventory(0).GetItemAmount(ore);if(h<=tgt+1)continue;for(int di=0;di<all.Count;di++){if(di==si)continue;var dInv=all[di].GetInventory(0);if(!InvNotFull(dInv))continue;double there=(double)dInv.GetItemAmount(ore);if(there>=tgt-1)continue;double am=Math.Min(tgt-there,h-tgt);if(am<=0)continue;XferType(ore.ToString(),all[si].GetInventory(0),dInv,am);h-=am;if(h<=tgt+1)break;}}}}
void S16_RefSort(){var all=new List<IMyRefinery>();all.AddRange(_ref);all.AddRange(_arc);foreach(var r in all){var items=new List<MyInventoryItem>();r.GetInventory(0).GetItems(items);if(items.Count<2)continue;int bi=0;double bs=double.MaxValue;for(int i=0;i<items.Count;i++){string s=items[i].Type.SubtypeId.ToString();MyDefinitionId id=default(MyDefinitionId);MyDefinitionId.TryParse(OB+T_INGOT+"/"+s,out id);double h=0;_gAmt.TryGetValue(id,out h);if(h<bs){bs=h;bi=i;}}if(bi!=0)r.GetInventory(0).TransferItemTo(r.GetInventory(0),bi,0,true,null);}}
void S17_InternalSort(){foreach(var b in _typedC){var inv=b.GetInventory(0);_itmScr.Clear();inv.GetItems(_itmScr);if(_itmScr.Count<2)continue;bool mg=true;int gd=0;while(mg&&gd<50){mg=false;gd++;_itmScr.Clear();inv.GetItems(_itmScr);var fs=new Dictionary<MyItemType,int>();for(int i=0;i<_itmScr.Count;i++){if(!fs.ContainsKey(_itmScr[i].Type))fs[_itmScr[i].Type]=i;}for(int i=_itmScr.Count-1;i>=0;i--){int f=fs[_itmScr[i].Type];if(i!=f){inv.TransferItemTo(inv,i,f,true,null);mg=true;}}}}if(showFill)UpdateFillNames();}
void UpdateFillNames(){foreach(var b in _typedC){var inv=b.GetInventory(0);float p=(float)inv.MaxVolume>0f?(float)inv.CurrentVolume/(float)inv.MaxVolume*100f:0f;string n=b.CustomName;int lb=n.LastIndexOf(" (");int rb=n.LastIndexOf("%)");if(lb>=0&&rb>lb)n=n.Substring(0,lb);b.CustomName=n+" ("+((int)p)+"%)";}}
void S18_Displays(){_lcdRescanTimer++;if(_lcdRescanTimer>=LCD_RESCAN){_lcdRescanTimer=0;BindLcds();}CDrawPB();CDrawMain();DrawAlert();P2Display();if(_displaySub==0)CDrawInv(_sfOre,"ORE STOCK",ORE_NAMES,T_ORE,CLR_ACCENT,_oreC);else if(_displaySub==1)CDrawInv(_sfIngot,"INGOT STOCK",INGOT_NAMES,T_INGOT,CLR_OK,_ingC);else if(_displaySub==2)CDrawInv(_sfComp,"COMPONENTS",COMP_NAMES,T_COMP,new Color(80,160,255),_cmpC);else if(_displaySub==3)CDrawInv(_sfAmmo,"AMMUNITION",AMMO_NAMES,T_AMMO,CLR_ERR,_ammoC);else if(_displaySub==4)CDrawKnown(_sfTools,"TOOLS & ITEMS",T_TOOL,new Color(180,120,255),_toolC,0);else if(_displaySub==5)CDrawCraft();else if(_displaySub==6)CDrawKnown(_sfFood,"FOOD & DRINKS",T_CON,new Color(255,180,60),_foodC,1);else if(_displaySub==7)CDrawKnown(_sfBot,"BOTTLES",T_GAS,new Color(80,200,255),_botC,2);else if(_displaySub==8)CDrawKnown(_sfSeed,"SEEDS",T_SEED,new Color(100,220,80),_seedC,0);else CDrawKnown(_sfIngI,"INGREDIENTS",T_CON,new Color(200,140,80),_ingIC,3);_displaySub++;if(_displaySub>9)_displaySub=0;}
bool InvNotFull(IMyInventory inv){float c=(float)inv.CurrentVolume,m=(float)inv.MaxVolume;if(m<=0)return false;return m*0.02f<(float)invBuffer?c<m*0.98f:c<m-(float)invBuffer;}
string InvName(IMyInventory x){foreach(var b in _all)for(int i=0;i<b.InventoryCount;i++)if(b.GetInventory(i)==x)return b.CustomName;return "?";}
double XferType(string ts,IMyInventory src,IMyInventory dst,double max){_itmScr.Clear();src.GetItems(_itmScr);double mv=0;for(int i=_itmScr.Count-1;i>=0;i--){if(!_itmScr[i].Type.ToString().Contains(ts.Contains("/")?ts:"/"+ts))continue;MyFixedPoint a=(MyFixedPoint)Math.Min((double)_itmScr[i].Amount,max-mv);if((double)a<=0)continue;if(src.TransferItemTo(dst,i,null,true,a)){mv+=(double)a;Log(DateTime.Now.ToString("HH:mm")+" "+_itmScr[i].Type.SubtypeId+" "+InvName(src)+" > "+InvName(dst));}if(mv>=max)break;}return mv;}
void Log(string m){_log.Add(m);if(_log.Count>20)_log.RemoveAt(0);}
string Fmt(double v){if(v>=1000000)return (v/1000000.0).ToString("F2")+"M";if(v>=1000)return (v/1000.0).ToString("F1")+"k";return ((int)v).ToString();}
void SetupSurf(IMyTextSurface s){var p=s as IMyTextPanel;long id=p!=null?p.EntityId:Me.EntityId;if(_initLcds.Contains(id)&&s.ContentType==ContentType.SCRIPT&&string.IsNullOrEmpty(s.Script))return;s.ContentType=ContentType.SCRIPT;s.Script="";s.ScriptBackgroundColor=CLR_BG;s.BackgroundColor=CLR_BG;_initLcds.Add(id);}
void DrawBar(MySpriteDrawFrame f,Vector2 pos,float bw,float bh,double cur,double max,Color col){float r=(max>0)?(float)Math.Min(cur/max,1.0):0f;f.Add(new MySprite(SpriteType.TEXTURE,"SquareSimple",pos+new Vector2(bw*0.5f,bh*0.5f),new Vector2(bw,bh),CLR_BAR_BG));if(r>0f)f.Add(new MySprite(SpriteType.TEXTURE,"SquareSimple",pos+new Vector2(bw*r*0.5f,bh*0.5f),new Vector2(bw*r,bh),col));}
void CT(MySpriteDrawFrame f,string s,Vector2 p,Color c,float z,TextAlignment a){var x=MySprite.CreateText(s,"Monospace",c,z,a);x.Position=p;f.Add(x);}
void CR(MySpriteDrawFrame f,Vector2 p,Vector2 z,Color c){f.Add(new MySprite(SpriteType.TEXTURE,"SquareSimple",p,z,c));}
string CN(string s){var b=new StringBuilder();for(int i=0;i<s.Length;i++){char c=s[i];if(c=='_'){b.Append(' ');continue;}if(i>0&&char.IsUpper(c)&&char.IsLower(s[i-1]))b.Append(' ');b.Append(c);}return b.ToString().Replace("Meal Pack ","");}
void CDrawPB(){var p=Me as IMyTextSurfaceProvider;if(p==null||p.SurfaceCount==0)return;var sf=p.GetSurface(0);SetupSurf(sf);Vector2 v=(sf.TextureSize-sf.SurfaceSize)*.5f,z=sf.SurfaceSize;using(var f=sf.DrawFrame()){CR(f,v+z*.5f,z,CLR_BG);CT(f,"AGM",v+z*.5f-new Vector2(0,28),CLR_ACCENT,1.6f,TextAlignment.CENTER);CT(f,"PHASE 2",v+z*.5f+new Vector2(0,42),CLR_DIM,.38f,TextAlignment.CENTER);}}
void CDrawMain(){int si=NextSurface(_sfMain,"main");if(si<0)return;var sf=_sfMain[si];SetupSurf(sf);Vector2 v=(sf.TextureSize-sf.SurfaceSize)*.5f,z=sf.SurfaceSize;float w=z.X,h=z.Y;using(var f=sf.DrawFrame()){CR(f,v+z*.5f,z,CLR_BG);CR(f,v+new Vector2(w*.5f,h*.07f),new Vector2(w,h*.14f),CLR_PANEL);CT(f,"AUTOGRID MANAGER",v+new Vector2(w*.5f,h*.025f),CLR_ACCENT,.62f,TextAlignment.CENTER);CT(f,"SYSTEMS",v+new Vector2(w*.04f,h*.24f),CLR_ACCENT,.40f,TextAlignment.LEFT);CR(f,v+new Vector2(w*.5f,h*.30f),new Vector2(w*.94f,2),CLR_ACCENT);CT(f,"Inventory",v+new Vector2(w*.05f,h*.37f),CLR_DIM,.30f,TextAlignment.LEFT);CT(f,_all.Count.ToString(),v+new Vector2(w*.27f,h*.37f),CLR_WHITE,.38f,TextAlignment.RIGHT);CT(f,"Assemblers",v+new Vector2(w*.39f,h*.37f),CLR_DIM,.30f,TextAlignment.LEFT);CT(f,_asm.Count.ToString(),v+new Vector2(w*.61f,h*.37f),CLR_WHITE,.38f,TextAlignment.RIGHT);CT(f,"Refineries",v+new Vector2(w*.72f,h*.37f),CLR_DIM,.30f,TextAlignment.LEFT);CT(f,(_ref.Count+_arc.Count).ToString(),v+new Vector2(w*.95f,h*.37f),CLR_WHITE,.38f,TextAlignment.RIGHT);CT(f,"STORAGE",v+new Vector2(w*.04f,h*.55f),CLR_ACCENT,.40f,TextAlignment.LEFT);CR(f,v+new Vector2(w*.5f,h*.61f),new Vector2(w*.94f,2),CLR_ACCENT);CT(f,"Ore "+_oreC.Count+"   Ingot "+_ingC.Count+"   Component "+_cmpC.Count+"   Ammo "+_ammoC.Count,v+new Vector2(w*.05f,h*.69f),CLR_WHITE,.31f,TextAlignment.LEFT);CT(f,"Tools "+_toolC.Count+"   Bottles "+_botC.Count+"   Food "+_foodC.Count+"   Seeds "+_seedC.Count+"   Ingredients "+_ingIC.Count,v+new Vector2(w*.05f,h*.78f),CLR_WHITE,.28f,TextAlignment.LEFT);CR(f,v+new Vector2(w*.5f,h-14),new Vector2(w,28),CLR_PANEL);CT(f,"AGM Phase 2",v+new Vector2(w*.5f,h-22),CLR_DIM,.28f,TextAlignment.CENTER);}}
void PScr(List<IMyTextSurface> ss,string title,List<string> lines,Color col){int si=NextSurface(ss,title);if(si<0)return;var sf=ss[si];SetupSurf(sf);int rows=12,pages=Math.Max(1,(int)Math.Ceiling(lines.Count/(double)rows)),pg=GetLcdPage(sf);if(pg>=pages){pg=0;SetLcdPage(sf,0);}Vector2 v=(sf.TextureSize-sf.SurfaceSize)*.5f,z=sf.SurfaceSize;float w=z.X,h=z.Y,rh=(h-70)/rows;using(var f=sf.DrawFrame()){CR(f,v+z*.5f,z,CLR_BG);int st=pg*rows;for(int j=0;j<rows&&st+j<lines.Count;j++){string s=lines[st+j];Color c=s.Contains("CRIT")||s.Contains("FULL")||s.Contains("DEPLETED")||s.Contains("LEAK")?CLR_ERR:s.Contains("LOW")||s.Contains("OFFLINE")||s.Contains("WARN")?CLR_WARN:CLR_WHITE;CT(f,s,v+new Vector2(w*.04f,46+j*rh),c,rh<28?.25f:.31f,TextAlignment.LEFT);}CR(f,v+new Vector2(w*.5f,18),new Vector2(w,36),CLR_PANEL);CT(f,title,v+new Vector2(w*.5f,7),col,.52f,TextAlignment.CENTER);if(pages>1)CT(f,"P"+(pg+1)+"/"+pages,v+new Vector2(w*.97f,7),col,.28f,TextAlignment.RIGHT);CR(f,v+new Vector2(w*.5f,h-11),new Vector2(w,22),CLR_PANEL);CT(f,"AGM Phase 2",v+new Vector2(w*.5f,h-18),CLR_DIM,.25f,TextAlignment.CENTER);}}
void P2Display(){if(_p2Display==0)DrawPower();else if(_p2Display==1)DrawFuel();else if(_p2Display==2)DrawDock();else if(_p2Display==3)DrawDef();else if(_p2Display==4)DrawProd();else DrawLog();_p2Display++;if(_p2Display>5)_p2Display=0;}
string PBar(double p){int n=(int)Math.Round(MathHelper.Clamp((float)p,0,100)/10);return "["+new string('|',n)+new string('.',10-n)+"] "+p.ToString("F1")+"%";}
void DScreen(List<IMyTextSurface> ss,string title,List<IMyTerminalBlock> bs,List<string> tx,List<double> va,List<double> mx,List<int> st,Color ac){int si=NextSurface(ss,title);if(si<0)return;var sf=ss[si];SetupSurf(sf);int rows=10,pages=Math.Max(1,(int)Math.Ceiling(bs.Count/(double)rows)),pg=GetLcdPage(sf);if(pg>=pages){pg=0;SetLcdPage(sf,0);}Vector2 v=(sf.TextureSize-sf.SurfaceSize)*.5f,z=sf.SurfaceSize;float w=z.X,h=z.Y,rh=(h-64)/rows;using(var f=sf.DrawFrame()){CR(f,v+z*.5f,z,CLR_BG);int q=pg*rows;for(int j=0;j<rows&&q+j<bs.Count;j++){int i=q+j;float y=v.Y+42+j*rh,ic=Math.Min(24,rh*.8f);try{f.Add(new MySprite(SpriteType.TEXTURE,bs[i].BlockDefinition.ToString(),new Vector2(v.X+w*.04f,y+rh*.38f),new Vector2(ic,ic),Color.White));}catch{}CT(f,tx[i],new Vector2(v.X+w*.08f,y),CLR_WHITE,rh<31?.25f:.3f,TextAlignment.LEFT);double m=mx[i]>0?mx[i]:1,r=Math.Min(va[i]/m,1);CR(f,new Vector2(v.X+w*.67f,y+rh*.32f),new Vector2(w*.28f,10),CLR_BAR_BG);if(r>0)CR(f,new Vector2(v.X+w*.53f+w*.28f*(float)r*.5f,y+rh*.32f),new Vector2(w*.28f*(float)r,10),ac);Color c=st[i]==2?CLR_ERR:st[i]==1?CLR_WARN:CLR_OK;CR(f,new Vector2(v.X+w*.91f,y+rh*.32f),new Vector2(13,13),c);CT(f,mx[i]>1?Fmt(va[i]):(va[i]>0?"ON":"OFF"),new Vector2(v.X+w*.98f,y),CLR_DIM,.25f,TextAlignment.RIGHT);}CR(f,v+new Vector2(w*.5f,18),new Vector2(w,36),CLR_PANEL);CT(f,title,v+new Vector2(w*.5f,7),ac,.52f,TextAlignment.CENTER);if(pages>1)CT(f,"P"+(pg+1)+"/"+pages,v+new Vector2(w*.97f,7),ac,.28f,TextAlignment.RIGHT);CR(f,v+new Vector2(w*.5f,h-11),new Vector2(w,22),CLR_PANEL);CT(f,"Green Online   Amber Offline/Depleted   Red Damaged",v+new Vector2(w*.5f,h-18),CLR_DIM,.22f,TextAlignment.CENTER);}}
int BState(IMyTerminalBlock b,bool depleted){var f=b as IMyFunctionalBlock;return f==null||!f.IsFunctional?2:!f.Enabled||depleted?1:0;}
void PowerDots(MySpriteDrawFrame f,string name,List<int> st,Vector2 v,float w,float y){int on=0;foreach(var q in st)if(q==0)on++;CT(f,name+"  "+on+"/"+st.Count+" ONLINE",v+new Vector2(w*.05f,y),CLR_WHITE,.34f,TextAlignment.LEFT);float x=v.X+w*.055f,sy=v.Y+y+27,sz=Math.Min(18,w*.035f),gap=sz+7;for(int i=0;i<st.Count;i++){if(x+sz>v.X+w*.96f){x=v.X+w*.055f;sy+=sz+6;}Color c=st[i]==2?CLR_ERR:st[i]==1?CLR_WARN:CLR_OK;CR(f,new Vector2(x+sz*.5f,sy+sz*.5f),new Vector2(sz,sz),c);x+=gap;}}
void PowerBar(MySpriteDrawFrame f,string name,double cur,double max,Vector2 v,float w,float y,Color c,string unit){double pc=max>0?cur/max*100:0;CT(f,name,v+new Vector2(w*.05f,y),CLR_WHITE,.32f,TextAlignment.LEFT);DrawBar(f,v+new Vector2(w*.31f,y+3),w*.50f,14,cur,max,c);CT(f,pc.ToString("F0")+"%  "+cur.ToString("F2")+"/"+max.ToString("F2")+" "+unit,v+new Vector2(w*.96f,y-2),CLR_DIM,.26f,TextAlignment.RIGHT);}
void DrawPower(){int si=NextSurface(_sfPower,"power");if(si<0)return;var sf=_sfPower[si];SetupSurf(sf);Vector2 v=(sf.TextureSize-sf.SurfaceSize)*.5f,z=sf.SurfaceSize;float w=z.X,h=z.Y;var rs=new List<int>();var hs=new List<int>();var u=MyItemType.MakeIngot("Uranium");foreach(var x in _pReact)rs.Add(BState(x,(double)x.GetInventory(0).GetItemAmount(u)<=0));foreach(var x in _pH2Eng)hs.Add(BState(x,false));double bc=0,bm=0,bo=0,bom=0,so=0,som=0,wo=0,wom=0;foreach(var x in _pBat){bc+=x.CurrentStoredPower;bm+=x.MaxStoredPower;bo+=x.CurrentOutput;bom+=x.MaxOutput;}foreach(var x in _pSolar){so+=x.CurrentOutput;som+=x.MaxOutput;}foreach(var x in _pWind){wo+=x.CurrentOutput;wom+=x.MaxOutput;}using(var f=sf.DrawFrame()){CR(f,v+z*.5f,z,CLR_BG);CR(f,v+new Vector2(w*.5f,20),new Vector2(w,40),CLR_PANEL);CT(f,"POWER & ENERGY",v+new Vector2(w*.5f,7),CLR_OK,.55f,TextAlignment.CENTER);float y=58;if(rs.Count>0){PowerDots(f,"REACTORS",rs,v,w,y);y+=68;}if(hs.Count>0){PowerDots(f,"HYDROGEN ENGINES",hs,v,w,y);y+=68;}CR(f,v+new Vector2(w*.5f,y-10),new Vector2(w*.9f,2),CLR_ACCENT);if(_pBat.Count>0){PowerBar(f,"BATTERY CHARGE",bc,bm,v,w,y+12,CLR_OK,"MWh");PowerBar(f,"BATTERY OUTPUT",bo,bom,v,w,y+52,new Color(80,200,255),"MW");y+=92;}if(_pSolar.Count>0){PowerBar(f,"SOLAR OUTPUT",so,som,v,w,y+12,CLR_WARN,"MW");y+=40;}if(_pWind.Count>0){PowerBar(f,"WIND OUTPUT",wo,wom,v,w,y+12,new Color(180,120,255),"MW");y+=40;}CR(f,v+new Vector2(w*.5f,h-11),new Vector2(w,22),CLR_PANEL);CT(f,"Green Online   Amber Offline/Empty   Red Damaged",v+new Vector2(w*.5f,h-18),CLR_DIM,.22f,TextAlignment.CENTER);}}
string BName(IMyTerminalBlock b,string key){string cd=b.CustomData;int p=cd.IndexOf(key+"=",StringComparison.OrdinalIgnoreCase);if(p<0)return b.CustomName;int e=cd.IndexOf('\n',p);return cd.Substring(p+key.Length+1,(e<0?cd.Length:e)-p-key.Length-1).Trim();}
void DrawFuel(){int si=NextSurface(_sfFuel,"fuel");if(si<0)return;var sf=_sfFuel[si];SetupSurf(sf);Vector2 v=(sf.TextureSize-sf.SurfaceSize)*.5f,z=sf.SurfaceSize;float w=z.X,h=z.Y;var ht=new List<int>();var ot=new List<int>();var gs=new List<int>();var vs=new List<int>();double hv=0,ov=0;int hc=0,oc=0;foreach(var x in _pTank){bool hy=x.BlockDefinition.SubtypeId.IndexOf("Hydrogen",StringComparison.OrdinalIgnoreCase)>=0;int q=BState(x,x.FilledRatio<.01);if(hy){ht.Add(q);hv+=x.FilledRatio;hc++;}else{ot.Add(q);ov+=x.FilledRatio;oc++;}}var ice=MyItemType.MakeOre("Ice");double ia=0;foreach(var x in _pGen){double a=(double)x.GetInventory(0).GetItemAmount(ice);ia+=a;gs.Add(BState(x,a<=pIceCrit));}foreach(var x in _pVent)vs.Add(!x.IsFunctional||!x.CanPressurize?2:x.GetOxygenLevel()<.95f?1:0);using(var f=sf.DrawFrame()){CR(f,v+z*.5f,z,CLR_BG);CR(f,v+new Vector2(w*.5f,20),new Vector2(w,40),CLR_PANEL);CT(f,"FUEL & LIFE SUPPORT",v+new Vector2(w*.5f,7),new Color(80,200,255),.55f,TextAlignment.CENTER);float y=58;if(ht.Count>0){PowerDots(f,"HYDROGEN TANKS",ht,v,w,y);y+=60;}if(ot.Count>0){PowerDots(f,"OXYGEN TANKS",ot,v,w,y);y+=60;}if(gs.Count>0){PowerDots(f,"O2/H2 GENERATORS",gs,v,w,y);y+=60;}if(vs.Count>0){PowerDots(f,"PRESSURIZED VENTS",vs,v,w,y);y+=60;}CR(f,v+new Vector2(w*.5f,y-8),new Vector2(w*.9f,2),CLR_ACCENT);if(hc>0){PowerBar(f,"HYDROGEN LEVEL",hv,hc,v,w,y+12,new Color(80,200,255),"");y+=40;}if(oc>0){PowerBar(f,"OXYGEN LEVEL",ov,oc,v,w,y+12,CLR_OK,"");y+=40;}if(gs.Count>0)PowerBar(f,"GENERATOR ICE",ia,pIceWarn*gs.Count,v,w,y+12,CLR_WARN,"kg");CR(f,v+new Vector2(w*.5f,h-11),new Vector2(w,22),CLR_PANEL);CT(f,"Green Ready   Amber Low/Pressurizing   Red Damaged/Leak",v+new Vector2(w*.5f,h-18),CLR_DIM,.22f,TextAlignment.CENTER);}}
string DockLine(IMyShipConnector d){if(d.Status!=MyShipConnectorStatus.Connected||d.OtherConnector==null)return BName(d,"dock")+": EMPTY";var o=d.OtherConnector;var bs=new List<IMyTerminalBlock>();GridTerminalSystem.GetBlocksOfType<IMyTerminalBlock>(bs,b=>b.CubeGrid.IsSameConstructAs(o.CubeGrid));double bc=0,bm=0,h=0;int hc=0;double cv=0,cm=0;foreach(var b in bs){var ba=b as IMyBatteryBlock;if(ba!=null){bc+=ba.CurrentStoredPower;bm+=ba.MaxStoredPower;}var t=b as IMyGasTank;if(t!=null&&t.BlockDefinition.SubtypeId.IndexOf("Hydrogen",StringComparison.OrdinalIgnoreCase)>=0){h+=t.FilledRatio;hc++;}for(int i=0;i<b.InventoryCount;i++){cv+=(double)b.GetInventory(i).CurrentVolume;cm+=(double)b.GetInventory(i).MaxVolume;}}return BName(d,"dock")+": OCCUPIED  PWR "+(bm>0?bc/bm*100:0).ToString("F0")+"% H2 "+(hc>0?h/hc*100:0).ToString("F0")+"% CARGO "+(cm>0?cv/cm*100:0).ToString("F0")+"%";}
void DrawDock(){var l=new List<string>();foreach(var d in _pDock)l.Add(DockLine(d));if(l.Count==0)l.Add("No [AGM-Dock] connectors");PScr(_sfDock,"DOCK MONITOR",l,CLR_ACCENT);}
void DrawDef(){int si=NextSurface(_sfDef,"defence");if(si<0)return;var sf=_sfDef[si];SetupSurf(sf);Vector2 v=(sf.TextureSize-sf.SurfaceSize)*.5f,z=sf.SurfaceSize;float w=z.X,h=z.Y;var ts=new List<int>();double ammo=0,ready=0;foreach(var x in _pTurret){double a=0;if(x.HasInventory){_itmScr.Clear();x.GetInventory(0).GetItems(_itmScr);foreach(var q in _itmScr)a+=(double)q.Amount;}ammo+=a;int q=!x.IsFunctional?2:!x.Enabled||a<=0?1:0;ts.Add(q);if(q==0)ready++;}using(var f=sf.DrawFrame()){CR(f,v+z*.5f,z,CLR_BG);CR(f,v+new Vector2(w*.5f,20),new Vector2(w,40),CLR_PANEL);CT(f,_safeMode?"DEFENCE - SAFE MODE":"DEFENCE - COMBAT",v+new Vector2(w*.5f,7),_safeMode?CLR_WARN:CLR_OK,.55f,TextAlignment.CENTER);PowerDots(f,"TAGGED TURRETS",ts,v,w,62);PowerBar(f,"TURRETS READY",ready,Math.Max(ts.Count,1),v,w,145,CLR_OK,"");PowerBar(f,"LOADED AMMO",ammo,Math.Max(ts.Count*20,1),v,w,190,CLR_ACCENT,"rounds");CT(f,_safeMode?"SAFE MODE: ALL TAGGED TURRETS DISABLED":"COMBAT MODE: TAGGED TURRETS ENABLED",v+new Vector2(w*.5f,250),_safeMode?CLR_WARN:CLR_OK,.32f,TextAlignment.CENTER);CR(f,v+new Vector2(w*.5f,h-11),new Vector2(w,22),CLR_PANEL);CT(f,"Green Ready   Amber Offline/Empty   Red Damaged",v+new Vector2(w*.5f,h-18),CLR_DIM,.22f,TextAlignment.CENTER);}}
string QName(IMyAssembler a){_queScr.Clear();a.GetQueue(_queScr);return _queScr.Count==0?"IDLE":_queScr[0].BlueprintId.SubtypeId+" x"+Fmt((double)_queScr[0].Amount);}
void DrawProd(){int si=NextSurface(_sfProd,"production");if(si<0)return;var sf=_sfProd[si];SetupSurf(sf);Vector2 v=(sf.TextureSize-sf.SurfaceSize)*.5f,z=sf.SurfaceSize;float w=z.X,h=z.Y;var aa=new List<int>();var rr=new List<int>();double aw=0,rw=0,aq=0,ri=0,rim=0;foreach(var x in _pAsm){int q=!x.IsFunctional?2:!x.Enabled||!x.IsProducing?1:0;aa.Add(q);if(x.IsProducing)aw++;_queScr.Clear();x.GetQueue(_queScr);foreach(var zq in _queScr)aq+=(double)zq.Amount;}foreach(var x in _pRef){int q=!x.IsFunctional?2:!x.Enabled||!x.IsProducing?1:0;rr.Add(q);if(x.IsProducing)rw++;ri+=(double)x.GetInventory(0).CurrentVolume;rim+=(double)x.GetInventory(0).MaxVolume;}using(var f=sf.DrawFrame()){CR(f,v+z*.5f,z,CLR_BG);CR(f,v+new Vector2(w*.5f,20),new Vector2(w,40),CLR_PANEL);CT(f,"PRODUCTION",v+new Vector2(w*.5f,7),new Color(180,120,255),.55f,TextAlignment.CENTER);float y=62;if(aa.Count>0){PowerDots(f,"ASSEMBLERS",aa,v,w,y);y+=72;}if(rr.Count>0){PowerDots(f,"REFINERIES",rr,v,w,y);y+=72;}CR(f,v+new Vector2(w*.5f,y-8),new Vector2(w*.9f,2),CLR_ACCENT);if(aa.Count>0){PowerBar(f,"ASSEMBLERS WORKING",aw,aa.Count,v,w,y+12,CLR_OK,"");PowerBar(f,"ASSEMBLY QUEUE",aq,Math.Max(aa.Count*100,1),v,w,y+52,new Color(180,120,255),"items");y+=92;}if(rr.Count>0){PowerBar(f,"REFINERIES WORKING",rw,rr.Count,v,w,y+12,CLR_OK,"");PowerBar(f,"REFINERY INPUT",ri,Math.Max(rim,1),v,w,y+52,CLR_ACCENT,"m3");}CR(f,v+new Vector2(w*.5f,h-11),new Vector2(w,22),CLR_PANEL);CT(f,"Green Working   Amber Idle/Offline   Red Damaged",v+new Vector2(w*.5f,h-18),CLR_DIM,.22f,TextAlignment.CENTER);}}
double CatFill(List<IMyTerminalBlock> x){double a=0,m=0;foreach(var b in x){a+=(double)b.GetInventory(0).CurrentVolume;m+=(double)b.GetInventory(0).MaxVolume;}return m>0?a/m*100:0;}
void DrawLog(){var l=new List<string>();l.Add("AUTOMATION");l.Add("Sorters: "+(_sortersOn?"ONLINE":"OFFLINE")+"  [sorterson / sortersoff]");l.Add("Quota control: "+(autoCraft?"AUTOMATIC":"PAUSED")+"  Craft low / disassemble excess");l.Add("CARGO LEVELS");l.Add("Ore "+CatFill(_oreC).ToString("F0")+"%  Ingot "+CatFill(_ingC).ToString("F0")+"%  Component "+CatFill(_cmpC).ToString("F0")+"%");l.Add("Ammo "+CatFill(_ammoC).ToString("F0")+"%  Tools "+CatFill(_toolC).ToString("F0")+"%  Bottles "+CatFill(_botC).ToString("F0")+"%");l.Add("Food "+CatFill(_foodC).ToString("F0")+"%  Seeds "+CatFill(_seedC).ToString("F0")+"%  Ingredients "+CatFill(_ingIC).ToString("F0")+"%");l.Add("CONVEYOR SORTERS");foreach(var s in _pSorter)l.Add(s.CustomName+": "+(s.Enabled?"ONLINE":"OFFLINE"));l.Add("RECENT AGM TRANSFERS");int st=Math.Max(0,_log.Count-5);for(int i=st;i<_log.Count;i++)l.Add(_log[i]);PScr(_sfLog,"LOGISTICS",l,new Color(100,220,180));}
void DrawAlert(){int si=NextSurface(_sfAlert,"alert");if(si<0)return;var sf=_sfAlert[si];SetupSurf(sf);Vector2 v=(sf.TextureSize-sf.SurfaceSize)*.5f,z=sf.SurfaceSize;Color c=_alertLevel==2?CLR_ERR:_alertLevel==1?CLR_WARN:CLR_OK;using(var f=sf.DrawFrame()){CR(f,v+z*.5f,z,c);CT(f,_alertLevel==2?"CRITICAL":_alertLevel==1?"WARNING":"OK",v+new Vector2(z.X*.5f,z.Y*.25f),CLR_BG,.8f,TextAlignment.CENTER);CT(f,_alertText,v+new Vector2(z.X*.5f,z.Y*.55f),CLR_BG,.28f,TextAlignment.CENTER);}}
void CFrame(IMyTextSurface sf,string title,int pg,int pages,Color col,List<string> n,List<MyDefinitionId> ids,List<double> vals,List<double> maxs,string footer){SetupSurf(sf);Vector2 v=(sf.TextureSize-sf.SurfaceSize)*.5f,z=sf.SurfaceSize;float w=z.X,h=z.Y,rh=28,y=42;using(var f=sf.DrawFrame()){CR(f,v+z*.5f,z,CLR_BG);int rows=Math.Min(n.Count,14),start=pg*14;for(int j=0;j<rows&&start+j<n.Count;j++){int i=start+j;float cy=v.Y+y+j*rh;try{f.Add(new MySprite(SpriteType.TEXTURE,ids[i].ToString(),new Vector2(v.X+w*.035f,cy+7),new Vector2(22,22),Color.White));}catch{}CT(f,CN(n[i]),new Vector2(v.X+w*.08f,cy),CLR_WHITE,.3f,TextAlignment.LEFT);double q=maxs[i]>0?maxs[i]:Math.Max(vals[i],1);float r=(float)Math.Min(vals[i]/q,1);CR(f,new Vector2(v.X+w*.69f,cy+7),new Vector2(w*.34f,10),CLR_BAR_BG);if(r>0)CR(f,new Vector2(v.X+w*.52f+w*.34f*r*.5f,cy+7),new Vector2(w*.34f*r,10),col);CT(f,Fmt(vals[i]),new Vector2(v.X+w*.97f,cy),CLR_WHITE,.3f,TextAlignment.RIGHT);}CR(f,v+new Vector2(w*.5f,18),new Vector2(w,36),CLR_PANEL);CT(f,title,v+new Vector2(w*.5f,7),CLR_ACCENT,.52f,TextAlignment.CENTER);if(pages>1)CT(f,"P"+(pg+1)+"/"+pages,v+new Vector2(w*.97f,7),CLR_ACCENT,.28f,TextAlignment.RIGHT);CR(f,v+new Vector2(w*.5f,h-11),new Vector2(w,22),CLR_PANEL);CT(f,footer,v+new Vector2(w*.5f,h-18),CLR_DIM,.25f,TextAlignment.CENTER);}}
void CDrawInv(List<IMyTextSurface> ss,string title,string[] names,string tid,Color col,List<IMyTerminalBlock> boxes){int si=NextSurface(ss,title);if(si<0)return;var n=new List<string>();var ids=new List<MyDefinitionId>();var vals=new List<double>();var qs=new List<double>();foreach(var x in names){var id=ResolveDisplayId(x,tid);double a=0;_gAmt.TryGetValue(id,out a);double q=DisplayQuota(id);if(a<=0&&q<=0)continue;n.Add(x);ids.Add(id);vals.Add(a);qs.Add(q);}int pages=Math.Max(1,(int)Math.Ceiling(n.Count/14.0)),pg=GetLcdPage(ss[si]);if(pg>=pages){pg=0;SetLcdPage(ss[si],0);}double vol=0,cap=0;foreach(var b in boxes){vol+=(double)b.GetInventory(0).CurrentVolume*1000;cap+=(double)b.GetInventory(0).MaxVolume*1000;}CFrame(ss[si],title,pg,pages,col,n,ids,vals,qs,Fmt(vol)+" / "+Fmt(cap)+" L");}
void CDrawKnown(List<IMyTextSurface> ss,string title,string tid,Color col,List<IMyTerminalBlock> boxes,int mode){var n=new List<string>();foreach(var k in _known){string s=k.SubtypeId.ToString(),t=k.TypeId.ToString();bool ok=mode==0?t.Contains(tid):mode==1?t.Contains(T_CON)&&IsFoodSub(s):mode==2?t.Contains(T_GAS)||t.Contains(T_OXY):(t.Contains(T_CON)||t.Contains(T_PHYS))&&IsIngredientSub(s);if(ok&&!n.Contains(s))n.Add(s);}n.Sort();CDrawInv(ss,title,n.ToArray(),tid,col,boxes);}
void CDrawCraft(){int si=NextSurface(_sfAcraft,"craft");if(si<0)return;var sf=_sfAcraft[si];SetupSurf(sf);var n=new List<string>();var ids=new List<MyDefinitionId>();var vals=new List<double>();var qs=new List<double>();var dis=new List<bool>();var cat=new List<bool>();string last="";if(_acraftCfg!=null){string cd=_acraftCfg.CustomData;int a=cd.IndexOf(ACRAFT_START),e=cd.IndexOf(ACRAFT_END);if(a>=0){int b=cd.IndexOf('\n',a)+1;if(e<0)e=cd.Length;foreach(var line in cd.Substring(b,e-b).Split('\n')){string x=line.Trim();int q=x.IndexOf('=');if(q<1||x.StartsWith("~")||x.StartsWith("@"))continue;string name=x.Substring(0,q).Trim(),amt=x.Substring(q+1).Trim();if(InList(name,IGNORE_AMMO))continue;bool d=amt.EndsWith("D",StringComparison.OrdinalIgnoreCase);if(d)amt=amt.Substring(0,amt.Length-1);double want;if(!double.TryParse(amt,out want)||want<0)continue;MyDefinitionId id;if(!TryResId(name,out id)){string typ=InList(name,AMMO_NAMES)?T_AMMO:name=="OxygenBottle"?T_OXY:name=="HydrogenBottle"?T_GAS:T_COMP;if(!MyDefinitionId.TryParse(OB+typ+"/"+name,out id))continue;}string it=id.TypeId.ToString(),group=it.Contains(T_AMMO)?"AMMUNITION":(it.Contains(T_OXY)||it.Contains(T_GAS))?"BOTTLES":"COMPONENTS";if(group!=last){n.Add(group);ids.Add(default(MyDefinitionId));vals.Add(0);qs.Add(0);dis.Add(false);cat.Add(true);last=group;}double have=0;_gAmt.TryGetValue(id,out have);n.Add(name);ids.Add(id);vals.Add(have);qs.Add(want);dis.Add(d);cat.Add(false);}}}int rows=Math.Max(9,(int)Math.Ceiling(n.Count/3.0)),pages=Math.Max(1,(int)Math.Ceiling(n.Count/(double)rows)),pg=GetLcdPage(sf);if(pg>=pages){pg=0;SetLcdPage(sf,0);}Vector2 v=(sf.TextureSize-sf.SurfaceSize)*.5f,z=sf.SurfaceSize;float w=z.X,h=z.Y,y=88,rh=Math.Min(30,(h-112)/rows),fs=rh<27?.25f:.3f;int wk=0;foreach(var x in _asm)if(x.IsProducing)wk++;using(var f=sf.DrawFrame()){CR(f,v+z*.5f,z,CLR_BG);int st=pg*rows;for(int j=0;j<rows&&st+j<n.Count;j++){int i=st+j;float yy=v.Y+y+j*rh;if(cat[i]){CR(f,new Vector2(v.X+w*.5f,yy+rh*.35f),new Vector2(w*.98f,rh*.8f),CLR_PANEL);CT(f,n[i],new Vector2(v.X+w*.03f,yy),CLR_ACCENT,fs,TextAlignment.LEFT);continue;}string stat="OK";Color c=CLR_OK;if(qs[i]==0){stat="OFF";c=CLR_DIM;}else if(dis[i]&&vals[i]>qs[i]){stat="DISM";c=CLR_WARN;}else if(!dis[i]&&vals[i]<qs[i]*.5){stat="LOW";c=CLR_ERR;}else if(!dis[i]&&vals[i]<qs[i]){stat="CRAFT";c=CLR_WARN;}if(c==CLR_ERR)CR(f,new Vector2(v.X+w*.5f,yy+rh*.3f),new Vector2(w*.98f,rh*.85f),new Color(80,15,15));else if(c==CLR_WARN&&!dis[i])CR(f,new Vector2(v.X+w*.5f,yy+rh*.3f),new Vector2(w*.98f,rh*.85f),new Color(50,40,5));try{f.Add(new MySprite(SpriteType.TEXTURE,ids[i].ToString(),new Vector2(v.X+w*.035f,yy+rh*.25f),new Vector2(rh*.75f,rh*.75f),Color.White));}catch{}CT(f,CN(n[i]),new Vector2(v.X+w*.08f,yy),qs[i]==0?CLR_DIM:CLR_WHITE,fs,TextAlignment.LEFT);CT(f,Fmt(vals[i]),new Vector2(v.X+w*.54f,yy),CLR_WHITE,fs,TextAlignment.RIGHT);CT(f,Fmt(qs[i]),new Vector2(v.X+w*.71f,yy),CLR_DIM,fs,TextAlignment.RIGHT);CT(f,stat,new Vector2(v.X+w*.80f,yy),c,fs,TextAlignment.LEFT);}if(n.Count==0)CT(f,"Set amounts in LCD Custom Data",v+z*.5f,CLR_DIM,.33f,TextAlignment.CENTER);CR(f,v+new Vector2(w*.5f,16),new Vector2(w,32),CLR_PANEL);CT(f,"AUTOCRAFTING",v+new Vector2(w*.5f,6),CLR_ACCENT,.55f,TextAlignment.CENTER);if(pages>1)CT(f,"P"+(pg+1)+"/"+pages,v+new Vector2(w*.97f,6),CLR_ACCENT,.28f,TextAlignment.RIGHT);CT(f,"Assemblers: "+wk+"/"+_asm.Count+" working",v+new Vector2(w*.03f,38),wk>0?CLR_OK:CLR_DIM,.33f,TextAlignment.LEFT);CR(f,v+new Vector2(w*.5f,62),new Vector2(w*.95f,1),CLR_ACCENT);CT(f,"ITEM",v+new Vector2(w*.08f,66),CLR_ACCENT,.3f,TextAlignment.LEFT);CT(f,"HAVE",v+new Vector2(w*.54f,66),CLR_ACCENT,.3f,TextAlignment.RIGHT);CT(f,"WANT",v+new Vector2(w*.71f,66),CLR_ACCENT,.3f,TextAlignment.RIGHT);CT(f,"STATUS",v+new Vector2(w*.80f,66),CLR_ACCENT,.3f,TextAlignment.LEFT);CR(f,v+new Vector2(w*.5f,h-11),new Vector2(w,22),CLR_PANEL);CT(f,"BP:"+_bpMap.Count+" Queue:"+_qAmt.Count,v+new Vector2(w*.5f,h-18),CLR_DIM,.26f,TextAlignment.CENTER);}}
int GetLcdPage(IMyTextSurface sf){var p=sf as IMyTextPanel;if(p==null)return 0;string cd=p.CustomData;if(string.IsNullOrEmpty(cd))return 0;int idx=cd.IndexOf("page=");if(idx<0)return 0;int end=cd.IndexOf('\n',idx);string val=end>=0?cd.Substring(idx+5,end-idx-5).Trim():cd.Substring(idx+5).Trim();int v;if(!int.TryParse(val,out v)||v<0)return 0;return v;}
void SetLcdPage(IMyTextSurface sf,int pg){var p=sf as IMyTextPanel;if(p==null)return;string cd=p.CustomData;int idx=cd.IndexOf("page=");string repl="page="+pg;if(idx>=0){int end=cd.IndexOf('\n',idx);cd=end>=0?cd.Substring(0,idx)+repl+cd.Substring(end):cd.Substring(0,idx)+repl;}else{cd=repl+"\n"+cd;}p.CustomData=cd;}
void AdvanceLcdPage(string keyword){var pans=new List<IMyTextPanel>();GridTerminalSystem.GetBlocksOfType<IMyTextPanel>(pans,p=>HasNameTag(p,AGM_TAG)&&LcdRole(p,keyword));foreach(var p in pans){int pg=GetLcdPage(p);SetLcdPage(p,pg+1);}}
void BindLcds(){_sfMain.Clear();_sfOre.Clear();_sfIngot.Clear();_sfComp.Clear();_sfAmmo.Clear();_sfTools.Clear();_sfAcraft.Clear();_sfAction.Clear();_sfPerf.Clear();_sfFood.Clear();_sfBot.Clear();_sfSeed.Clear();_sfIngI.Clear();_sfPower.Clear();_sfFuel.Clear();_sfDock.Clear();_sfDef.Clear();_sfProd.Clear();_sfAlert.Clear();_sfLog.Clear();var pans=new List<IMyTextPanel>();GridTerminalSystem.GetBlocksOfType<IMyTextPanel>(pans,p=>(HasNameTag(p,AGM_TAG)||HasTag(p,P_ALERT))&&!IsExcluded(p));foreach(var p in pans){SetupSurf(p);if(!p.CustomData.Contains("page="))p.CustomData="page=0\n"+p.CustomData;if(HasTag(p,P_ALERT))_sfAlert.Add(p);else if(LcdRole(p,"Power"))_sfPower.Add(p);else if(LcdRole(p,"Fuel"))_sfFuel.Add(p);else if(LcdRole(p,"Dock"))_sfDock.Add(p);else if(LcdRole(p,"Defence")||LcdRole(p,"Defense"))_sfDef.Add(p);else if(LcdRole(p,"Production"))_sfProd.Add(p);else if(LcdRole(p,"Logistics"))_sfLog.Add(p);else if(LcdRole(p,"Main"))_sfMain.Add(p);else if(LcdRole(p,"Autocraft")||LcdRole(p,"Crafting"))_sfAcraft.Add(p);else if(LcdRole(p,"OreStock")||LcdRole(p,"Ore"))_sfOre.Add(p);else if(LcdRole(p,"IngotStock")||LcdRole(p,"Ingot"))_sfIngot.Add(p);else if(LcdRole(p,"ComponentStock")||LcdRole(p,"Component"))_sfComp.Add(p);else if(LcdRole(p,"AmmoStock")||LcdRole(p,"Ammo"))_sfAmmo.Add(p);else if(LcdRole(p,"ToolStock")||LcdRole(p,"Tools"))_sfTools.Add(p);else if(LcdRole(p,"FoodStock")||LcdRole(p,"Food"))_sfFood.Add(p);else if(LcdRole(p,"BottleStock")||LcdRole(p,"Bottles"))_sfBot.Add(p);else if(LcdRole(p,"SeedStock")||LcdRole(p,"Seeds"))_sfSeed.Add(p);else if(LcdRole(p,"IngredientStock")||LcdRole(p,"Ingredients"))_sfIngI.Add(p);else _sfMain.Add(p);}}
bool InList(string name,string[] list){foreach(var n in list)if(n.Equals(name,StringComparison.OrdinalIgnoreCase))return true;return false;}
bool IsIngredientSub(string name){return InList(name,ING_SUBS)||InList(name,PHYS_ING);}
bool IsFoodSub(string name){return InList(name,FOOD_SUBS)||name.StartsWith("MealPack_",StringComparison.OrdinalIgnoreCase);}
string ShortType(MyDefinitionId id){string t=id.TypeId.ToString();int i=t.LastIndexOf('_');return i>=0?t.Substring(i+1):t;}
double DisplayQuota(MyDefinitionId id){double q;if(_displayQuota.TryGetValue(ShortType(id)+"/"+id.SubtypeId.ToString(),out q))return q;if(_displayQuota.TryGetValue(id.SubtypeId.ToString(),out q))return q;return 0;}
int NextSurface(List<IMyTextSurface> surfs,string key){if(surfs.Count==0)return -1;int i=0;_drawCursor.TryGetValue(key,out i);if(i<0||i>=surfs.Count)i=0;_drawCursor[key]=(i+1)%surfs.Count;return i;}
MyDefinitionId ResolveDisplayId(string name,string preferred){MyDefinitionId id=default(MyDefinitionId);string pt=preferred;if(preferred==T_CON&&InList(name,PHYS_ING))pt=T_PHYS;MyDefinitionId.TryParse(OB+pt+"/"+name,out id);if(_gAmt.ContainsKey(id)||DisplayQuota(id)>0)return id;if(preferred==T_GAS){MyDefinitionId.TryParse(OB+T_OXY+"/"+name,out id);if(_gAmt.ContainsKey(id)||DisplayQuota(id)>0)return id;}foreach(var k in _known)if(k.SubtypeId.ToString()==name&&(k.TypeId.ToString().Contains(pt)||(preferred==T_GAS&&k.TypeId.ToString().Contains(T_OXY))))return k;return id;}
void DrawBoot(float p,string msg){var pb=Me as IMyTextSurfaceProvider;if(pb==null||pb.SurfaceCount==0)return;var sf=pb.GetSurface(0);SetupSurf(sf);Vector2 vp=(sf.TextureSize-sf.SurfaceSize)*0.5f,sz=sf.SurfaceSize;float w=sz.X,h=sz.Y;using(var f=sf.DrawFrame()){f.Add(new MySprite(SpriteType.TEXTURE,"SquareSimple",vp+sz*0.5f,sz,CLR_BG));f.Add(new MySprite(SpriteType.TEXTURE,"SquareSimple",vp+new Vector2(w*0.5f,4f),new Vector2(w,6f),CLR_ACCENT));var t1=MySprite.CreateText("[AGM]","Monospace",CLR_ACCENT,0.9f,TextAlignment.CENTER);t1.Position=vp+new Vector2(w*0.5f,h*0.18f);f.Add(t1);var t2=MySprite.CreateText("AUTOGRID MANAGER","Monospace",CLR_WHITE,0.5f,TextAlignment.CENTER);t2.Position=vp+new Vector2(w*0.5f,h*0.35f);f.Add(t2);var t3=MySprite.CreateText("v3.0","Monospace",CLR_DIM,0.38f,TextAlignment.CENTER);t3.Position=vp+new Vector2(w*0.5f,h*0.46f);f.Add(t3);float bw=w*0.80f,bh=h*0.07f,bx=vp.X+(w-bw)*0.5f,by=vp.Y+h*0.58f;f.Add(new MySprite(SpriteType.TEXTURE,"SquareSimple",new Vector2(bx+bw*0.5f,by+bh*0.5f),new Vector2(bw,bh),CLR_BAR_BG));float fw=bw*MathHelper.Clamp(p,0f,1f);if(fw>2f)f.Add(new MySprite(SpriteType.TEXTURE,"SquareSimple",new Vector2(bx+fw*0.5f,by+bh*0.5f),new Vector2(fw,bh),CLR_ACCENT));var ml=MySprite.CreateText(msg,"Monospace",CLR_DIM,0.32f,TextAlignment.LEFT);ml.Position=vp+new Vector2(w*0.04f,h*0.76f);f.Add(ml);var pl=MySprite.CreateText(((int)(p*100))+"%","Monospace",CLR_ACCENT,0.38f,TextAlignment.RIGHT);pl.Position=vp+new Vector2(w*0.96f,h*0.75f);f.Add(pl);f.Add(new MySprite(SpriteType.TEXTURE,"SquareSimple",vp+new Vector2(w*0.5f,h-4f),new Vector2(w,6f),CLR_ACCENT));}}
void WriteStockTmpl(IMyTerminalBlock b){if(b.CustomData.Contains(STOCK_START))return;var sb=new StringBuilder();sb.Append(STOCK_START);sb.Append("\n");sb.Append("~ amount=exact, amountM=minimum, amountL=limit, amountP=pinned, all=fill\n");sb.Append("~ Use Type/Subtype for ambiguous or modded items\n");sb.Append("SteelPlate=1000\nConstruction=500\nMotor=200\nComputer=100\nMetalGrid=100\n");sb.Append("InteriorPlate=500\nSmallTube=200\nLargeTube=50\nDisplay=50\nBulletproofGlass=50\n");sb.Append("GravityGenerator=10\nSuperconductor=50\nThrust=50\nPowerCell=50\n");sb.Append("RadioCommunication=20\nDetector=10\nMedical=10\nSolarCell=20\nReactor=10\nExplosives=0\n");foreach(var ammo in AMMO_NAMES)sb.Append(ammo+"=0\n");sb.Append("WelderItem=0\nAngleGrinderItem=0\nHandDrillItem=0\n");sb.Append(STOCK_END);sb.Append("\n");b.CustomData=sb.ToString()+b.CustomData;}
void WriteAcraftTmpl(IMyTextPanel p){if(p.CustomData.Contains(ACRAFT_START))return;var sb=new StringBuilder();sb.Append(ACRAFT_START);sb.Append("\n");sb.Append("SteelPlate=0\nConstruction=0\nMotor=0\nComputer=0\nMetalGrid=0\n");sb.Append("InteriorPlate=0\nSmallTube=0\nLargeTube=0\nDisplay=0\nBulletproofGlass=0\n");sb.Append("GravityGenerator=0\nSuperconductor=0\nThrust=0\nPowerCell=0\n");sb.Append("RadioCommunication=0\nDetector=0\nMedical=0\nSolarCell=0\nReactor=0\nExplosives=0\n");foreach(var ammo in AMMO_NAMES)sb.Append(ammo+"=0\n");foreach(var bottle in BOTTLE_NAMES)sb.Append(bottle+"=20\n");sb.Append("WelderItem=0\nAngleGrinderItem=0\nHandDrillItem=0\n");sb.Append(ACRAFT_END);sb.Append("\n");p.CustomData=sb.ToString();}
bool IsOnExcludedGrid(IMyTerminalBlock b){return _excl.Contains(b.CubeGrid);}
